import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface SurveyAnswers {
  name: string;
  email: string;
  satisfaction: string;
  featureInterests: string[];
  comments: string;
}

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  submit?: (answers: SurveyAnswers) => Promise<void> | void;
}

const defaultProps: Props = {
  featureOptions: ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels: [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  submit: async () => {},
};

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = defaultProps.featureOptions,
    satisfactionLabels = defaultProps.satisfactionLabels,
    submit = defaultProps.submit,
  } = props;

  const totalSteps = 5;
  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');

  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });

  const [submitting, setSubmitting] = useState<boolean>(false);
  const [submitState, setSubmitState] = useState<'idle' | 'success' | 'error'>('idle');
  const [submitMessage, setSubmitMessage] = useState<string>('');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailRegex.test(email)
      ? 'Please enter a valid email address.'
      : '';

  const step2Options = useMemo(
    () =>
      satisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [satisfactionLabels]
  );

  const step1Valid = name.trim().length > 0 && emailRegex.test(email);
  const step2Valid = satisfaction.length > 0;
  const step3Valid = true;
  const step4Valid = comments.length <= 500;
  const canGoNext =
    (step === 1 && step1Valid) ||
    (step === 2 && step2Valid) ||
    (step === 3 && step3Valid) ||
    (step === 4 && step4Valid);

  const progressValue = (step / totalSteps) * 100;

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const handleNext = () => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    if (step < totalSteps) setStep((s) => s + 1);
  };

  const handleBack = () => {
    if (step > 1 && !submitting) setStep((s) => s - 1);
  };

  const answers: SurveyAnswers = {
    name: name.trim(),
    email: email.trim(),
    satisfaction,
    featureInterests,
    comments,
  };

  const handleSubmit = async () => {
    setSubmitState('idle');
    setSubmitMessage('');
    setSubmitting(true);
    try {
      await submit?.(answers);
      setSubmitState('success');
      setSubmitMessage('Survey submitted successfully.');
    } catch (error) {
      setSubmitState('error');
      setSubmitMessage('Failed to submit survey. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-live="polite"
          >
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        {submitState !== 'idle' && (
          <Alert
            variant={submitState === 'success' ? 'success' : 'error'}
            title={submitState === 'success' ? 'Success' : 'Submission Error'}
          >
            {submitMessage}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Contact Information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              placeholder="Enter your name"
              error={nameError}
              onBlur={() => setTouched((t) => ({ ...t, name: true }))}
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              placeholder="Enter your email"
              error={emailError}
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you? (1-5)"
              value={satisfaction}
              onChange={setSatisfaction}
              options={step2Options}
              direction="vertical"
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply
            </Text>
            <Stack gap={8}>
              {featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              placeholder="Share any additional thoughts..."
              helperText="Maximum 500 characters."
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              shadow="none"
              border
              radius="md"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {answers.name || '—'}</Text>
                <Text variant="body"><strong>Email:</strong> {answers.email || '—'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {answers.satisfaction
                    ? `${answers.satisfaction} - ${satisfactionLabels[Number(answers.satisfaction) - 1] ?? ''}`
                    : '—'}
                </Text>
                <Text variant="body">
                  <strong>Feature Interests:</strong>{' '}
                  {answers.featureInterests.length > 0
                    ? answers.featureInterests.join(', ')
                    : 'None selected'}
                </Text>
                <Text variant="body">
                  <strong>Comments:</strong> {answers.comments || 'No comments'}
                </Text>
              </Stack>
            </Card>
            <Button
              variant="primary"
              size="md"
              onClick={handleSubmit}
              loading={submitting}
              disabled={submitting}
              aria-label="Submit Survey"
            >
              Submit Survey
            </Button>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={8}>
          <Button
            variant="ghost"
            size="md"
            onClick={handleBack}
            disabled={step === 1 || submitting}
            aria-label="Back"
          >
            Back
          </Button>
          {step < totalSteps && (
            <Button
              variant="primary"
              size="md"
              onClick={handleNext}
              disabled={!canGoNext || submitting}
              aria-label="Next"
            >
              Next
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

GeneratedComponent.defaultProps = defaultProps;

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  lanthanide: 'var(--ggui-color-info-500, #06b6d4)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  'post-transition metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [search, setSearch] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, search]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category && el.category.trim()) set.add(el.category);
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [elements]);

  const selectedElement =
    elements.find((el) => el.atomicNumber === selectedAtomicNumber) ?? null;

  return (
    <Card
      padding={16}
      shadow="sm"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      } as React.CSSProperties}
    >
      <Stack gap={16}>
        <Text variant="label" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={search}
          onChange={setSearch}
          placeholder="Search by name or symbol"
          aria-label="Search elements by name or symbol"
        />

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            padding: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          {filteredElements.map((el, index) => {
            const categoryKey = (el.category ?? 'unknown').toLowerCase();
            const catColor = categoryColorMap[categoryKey] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
            const isSelected = selectedAtomicNumber === el.atomicNumber;
            const atomicNumberText = el.atomicNumber != null ? String(el.atomicNumber) : '—';
            const symbolText = el.symbol ?? '?';

            return (
              <Button
                key={`${el.atomicNumber ?? 'na'}-${el.symbol ?? 'na'}-${index}`}
                variant="ghost"
                size="sm"
                onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                aria-label={`Select element ${el.name ?? 'Unknown'} (${symbolText})`}
                style={{
                  gridColumn: el.col ?? 'auto',
                  gridRow: el.row ?? 'auto',
                  minHeight: '56px',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  background: 'var(--ggui-color-surface, #fafafa)',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' : 'none',
                  transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                  position: 'relative',
                }}
              >
                <span
                  style={{
                    position: 'absolute',
                    top: '4px',
                    left: '6px',
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    lineHeight: 1,
                  }}
                >
                  {atomicNumberText}
                </span>
                <span
                  style={{
                    fontSize: 'var(--ggui-font-size-lg, 18px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    textAlign: 'center',
                    display: 'inline-block',
                    width: '100%',
                  }}
                >
                  {symbolText}
                </span>
                <span
                  aria-hidden="true"
                  style={{
                    position: 'absolute',
                    right: '4px',
                    bottom: '4px',
                    width: '8px',
                    height: '8px',
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    background: catColor,
                  }}
                />
              </Button>
            );
          })}
        </Box>

        <Card
          padding={12}
          shadow="none"
          radius="md"
          border
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          } as React.CSSProperties}
        >
          {selectedElement ? (
            <Stack gap={6}>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Element Details
              </Text>
              <Text variant="body"><strong>Name:</strong> {selectedElement.name ?? '—'}</Text>
              <Text variant="body"><strong>Symbol:</strong> {selectedElement.symbol ?? '—'}</Text>
              <Text variant="body"><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}</Text>
              <Text variant="body"><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}</Text>
              <Text variant="body"><strong>Category:</strong> {selectedElement.category ?? '—'}</Text>
            </Stack>
          ) : (
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view its details.
            </Text>
          )}
        </Card>

        <Card
          padding={12}
          shadow="none"
          radius="md"
          border
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          } as React.CSSProperties}
        >
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Category Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((category) => {
                const tokenColor =
                  categoryColorMap[category.toLowerCase()] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
                return (
                  <Stack key={category} direction="horizontal" align="center" gap={6}>
                    <span
                      aria-hidden="true"
                      style={{
                        width: '10px',
                        height: '10px',
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: tokenColor,
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {category}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type RenderMessage = { sender: string; text: string; timestamp: string };

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount = 0,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<RenderMessage[]>([]);
  const listRef = useRef<HTMLDivElement>(null);

  const normalizedMessages = useMemo<RenderMessage[]>(
    () =>
      messages.map((m) => ({
        sender: m.sender || '',
        text: m.text || '',
        timestamp: m.timestamp || '',
      })),
    [messages]
  );

  const allMessages = useMemo(
    () => [...normalizedMessages, ...streamMessages],
    [normalizedMessages, streamMessages]
  );

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = customEvent.detail;
      if (!payload) return;
      setStreamMessages((prev) => [
        ...prev,
        {
          sender: payload.sender || '',
          text: payload.text || '',
          timestamp: payload.timestamp || new Date().toISOString(),
        },
      ]);
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) return iso;
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const onSubmit = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      radius="lg"
      shadow="sm"
      border
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            {title}
          </Text>
          <Badge variant="primary" size="sm">
            {participantCount}
          </Badge>
        </Stack>

        <Card
          padding="var(--ggui-spacing-2, 8px)"
          border
          shadow="none"
          radius="md"
        >
          <Stack
            gap="var(--ggui-spacing-2, 8px)"
            style={{
              maxHeight: 'var(--chat-list-height, 360px)',
              overflowY: 'auto',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
            // @ts-expect-error primitive forwards ref in runtime
            ref={listRef}
            aria-label="Message list"
          >
            {allMessages.map((message, index) => {
              const isMine = message.sender === currentUser;
              const prevSender = index > 0 ? allMessages[index - 1].sender : undefined;
              const showSenderHeader = prevSender !== message.sender;

              return (
                <Stack
                  key={`${message.sender}-${message.timestamp}-${index}`}
                  align={isMine ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  {showSenderHeader && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="div"
                    >
                      {message.sender}
                    </Text>
                  )}

                  <Card
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                    radius="lg"
                    shadow="none"
                    border
                    style={{
                      background: isMine
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderColor: isMine
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-outline, #d4d4d8)',
                      maxWidth: '80%',
                      transition: 'background-color 200ms ease-in-out, border-color 200ms ease-in-out',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text
                        variant="bodySmall"
                        color={isMine ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                        as="div"
                      >
                        {message.text}
                      </Text>
                      <Text
                        variant="caption"
                        color={
                          isMine
                            ? 'var(--ggui-color-primary-100, #e0f2fe)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                        }
                        align={isMine ? 'right' : 'left'}
                        as="div"
                      >
                        {formatTime(message.timestamp)}
                      </Text>
                    </Stack>
                  </Card>
                </Stack>
              );
            })}
          </Stack>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <Input
            value={draft}
            onChange={setDraft}
            placeholder="Type a message..."
            aria-label="Compose message"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                onSubmit();
              }
            }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={onSubmit}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const { stocks = [], lastUpdated } = props;

  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const detail = customEvent.detail;

      if (detail?.stocks) {
        setLiveStocks(detail.stocks);
      }
      if (detail?.lastUpdated) {
        setLiveLastUpdated(detail.lastUpdated);
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', onAgentData as EventListener);
    const timer = window.setTimeout(() => setIsConnecting(false), 2000);

    return () => {
      window.removeEventListener('ggui:agent-data', onAgentData as EventListener);
      window.clearTimeout(timer);
    };
  }, []);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const d = new Date(liveLastUpdated);
    if (Number.isNaN(d.getTime())) return liveLastUpdated;
    return d.toLocaleString();
  }, [liveLastUpdated]);

  const isLoading = !liveStocks || liveStocks.length === 0;

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      border
      radius="lg"
      shadow="sm"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{ flexWrap: 'wrap', rowGap: 'var(--ggui-spacing-2, 8px)' }}
        >
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-label="Market Watch"
          >
            Market Watch
          </Text>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            {isConnecting && <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />}
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {isConnecting ? 'Connecting live feed…' : 'Live'}
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedLastUpdated}
            </Text>
          </Stack>
        </Stack>

        {isLoading ? (
          <Stack align="center" gap="var(--ggui-spacing-2, 8px)" aria-live="polite">
            <Spinner size={24} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Loading stock prices…
            </Text>
          </Stack>
        ) : (
          <div
            role="list"
            aria-label="Stock ticker cards"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {liveStocks.map((stock, idx) => {
              const symbol = stock.symbol ?? '—';
              const name = stock.name ?? 'Unknown Company';
              const price = stock.price ?? 0;
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const positive = change >= 0;
              const color = positive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const arrow = positive ? '▲' : '▼';

              return (
                <Card
                  key={`${symbol}-${idx}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  border
                  shadow="sm"
                  radius="md"
                  role="listitem"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: color,
                    transition:
                      'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="3xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-label={`Ticker ${symbol}`}
                    >
                      {symbol}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {name}
                    </Text>
                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                      aria-label={`Current price ${price.toFixed(2)}`}
                    >
                      ${price.toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="label" color={color}>
                        {positive ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text variant="label" color={color} aria-label={`Change percentage ${changePercent.toFixed(2)} percent`}>
                        {arrow} {positive ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </div>
        )}
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionIcon(condition: string): string {
  const normalized = condition.toLowerCase();

  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rainy') || normalized.includes('drizzle') || normalized.includes('rain')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snowy') || normalized.includes('snow')) return '❄️';

  return '🌤️';
}

export default function GeneratedComponent({
  city = '—',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
