import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button,
  Progress,
  Alert,
  Container,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey callback */
  onSubmit?: (payload: {
    name: string;
    email: string;
    satisfaction: { value: string; label: string };
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

export default function GeneratedComponent({
  featureOptions = ['Analytics', 'Automation', 'Integrations', 'Reporting'],
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  onSubmit = async () => undefined,
}: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [nameTouched, setNameTouched] = useState(false);
  const [email, setEmail] = useState('');
  const [emailTouched, setEmailTouched] = useState(false);
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [submitState, setSubmitState] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');
  const [submitError, setSubmitError] = useState('');

  const totalSteps = 5;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const nameError = nameTouched && !name.trim() ? 'Name is required' : '';
  const emailError =
    emailTouched && !email.trim()
      ? 'Email is required'
      : emailTouched && !emailRegex.test(email)
      ? 'Please enter a valid email address'
      : '';

  const step1Valid = !!name.trim() && !!email.trim() && emailRegex.test(email);
  const step2Valid = !!satisfaction;
  const canNext =
    (step === 1 && step1Valid) ||
    (step === 2 && step2Valid) ||
    step === 3 ||
    step === 4 ||
    step === 5;

  const satisfactionOptions = useMemo(
    () =>
      satisfactionLabels.slice(0, 5).map((label, idx) => ({
        value: String(idx + 1),
        label: `${idx + 1} - ${label}`,
      })),
    [satisfactionLabels]
  );

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? Array.from(new Set([...prev, feature])) : prev.filter((f) => f !== feature)
    );
  };

  const next = () => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const back = () => setStep((s) => Math.max(1, s - 1));

  const handleSubmit = async () => {
    setSubmitState('submitting');
    setSubmitError('');
    try {
      await onSubmit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: {
          value: satisfaction,
          label: satisfactionOptions.find((o) => o.value === satisfaction)?.label ?? '',
        },
        featureInterests,
        comments,
      });
      setSubmitState('success');
    } catch (e) {
      setSubmitState('error');
      setSubmitError(e instanceof Error ? e.message : 'Something went wrong while submitting.');
    }
  };

  return (
    <Container maxWidth="md" padding={16}>
      <Card
        shadow="md"
        radius="lg"
        padding={20}
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          color: 'var(--ggui-color-onSurface, #18181b)',
        } as React.CSSProperties}
      >
        <Stack gap={16}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} of {totalSteps}
            </Text>
            <Progress value={step} max={totalSteps} size="md" />
          </Stack>

          <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
            Multi-step Survey
          </Heading>

          {submitState === 'success' && (
            <Alert variant="success" title="Survey submitted">
              Thank you for your feedback.
            </Alert>
          )}
          {submitState === 'error' && (
            <Alert variant="error" title="Submission failed">
              {submitError}
            </Alert>
          )}

          {step === 1 && (
            <Stack gap={12}>
              <Input
                label="Name"
                value={name}
                onChange={(v) => {
                  setName(v);
                  if (!nameTouched) setNameTouched(true);
                }}
                required
                error={nameError}
                placeholder="Enter your name"
                aria-label="Name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(v) => {
                  setEmail(v);
                  if (!emailTouched) setEmailTouched(true);
                }}
                required
                error={emailError}
                placeholder="you@example.com"
                aria-label="Email"
              />
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionOptions}
              error={!satisfaction ? 'Please select a rating' : undefined}
            />
          )}

          {step === 3 && (
            <Stack gap={8}>
              <Text variant="label">Which features interest you?</Text>
              {featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <TextArea
              label="Additional comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              placeholder="Share any additional thoughts..."
              helperText="Maximum 500 characters"
            />
          )}

          {step === 5 && (
            <Stack gap={10}>
              <Text variant="label">Review your answers</Text>
              <Card
                padding={12}
                radius="md"
                shadow="none"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                }}
              >
                <Stack gap={6}>
                  <Text><strong>Name:</strong> {name || '-'}</Text>
                  <Text><strong>Email:</strong> {email || '-'}</Text>
                  <Text>
                    <strong>Satisfaction:</strong>{' '}
                    {satisfactionOptions.find((o) => o.value === satisfaction)?.label || '-'}
                  </Text>
                  <Text>
                    <strong>Feature interests:</strong>{' '}
                    {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                  </Text>
                  <Text>
                    <strong>Comments:</strong> {comments.trim() || 'No comments'}
                  </Text>
                </Stack>
              </Card>
            </Stack>
          )}

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={back}
              disabled={step === 1 || submitState === 'submitting'}
            >
              Back
            </Button>

            {step < totalSteps ? (
              <Button
                variant="primary"
                onClick={next}
                disabled={!canNext || submitState === 'submitting'}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleSubmit}
                loading={submitState === 'submitting'}
                disabled={submitState === 'submitting'}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

export default function GeneratedComponent({ elements = [] }: Props) {
  const [query, setQuery] = useState<string>('');
  const [selected, setSelected] = useState<Props['elements'][number] | null>(null);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => set.add((el.category || 'unknown').toLowerCase()));
    return Array.from(set).sort();
  }, [elements]);

  const getCategoryColor = (category?: string) =>
    categoryColorMap[(category || 'unknown').toLowerCase()] ||
    'var(--ggui-color-neutral-400, #9ca3af)';

  const selectedElement =
    selected && filteredElements.some((el) => el.atomicNumber === selected.atomicNumber)
      ? selected
      : null;

  return (
    <Card
      padding={20}
      shadow="md"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol..."
        />

        <Card
          padding={12}
          border
          radius="md"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {filteredElements.map((el, idx) => {
              const categoryColor = getCategoryColor(el.category);
              return (
                <Button
                  key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? idx}`}
                  variant="ghost"
                  size="sm"
                  onPress={() => setSelected(el)}
                  aria-label={`${el.name || 'Unknown'} (${el.symbol || '?'})`}
                  style={{
                    gridColumn: el.col || undefined,
                    gridRow: el.row || undefined,
                    minHeight: 56,
                    padding: 6,
                    position: 'relative',
                    border: `1px solid var(--ggui-color-outlineVariant, #e4e4e7)`,
                    background:
                      selectedElement?.atomicNumber === el.atomicNumber
                        ? 'var(--ggui-color-container, #ede9fe)'
                        : 'var(--ggui-color-surface, #fafafa)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    outline: `2px solid ${categoryColor}`,
                    outlineOffset: -2,
                    transition: 'all 200ms ease',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: 4,
                      left: 6,
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      lineHeight: 1,
                    }}
                  >
                    {el.atomicNumber ?? ''}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-lg, 18px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      textAlign: 'center',
                      width: '100%',
                    }}
                  >
                    {el.symbol || '?'}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={16}
          radius="md"
          shadow="none"
          border
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Name: {selectedElement.name || '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Symbol: {selectedElement.symbol || '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Atomic Number: {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Atomic Weight: {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Category: {selectedElement.category || 'unknown'}
                </Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Click an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          radius="md"
          shadow="none"
          border
          style={{
            background: 'var(--ggui-color-surface, #fafafa)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((category) => (
                <Stack
                  key={category}
                  direction="horizontal"
                  align="center"
                  gap={6}
                  style={{
                    padding: '4px 8px',
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  }}
                >
                  <span
                    aria-hidden="true"
                    style={{
                      width: 10,
                      height: 10,
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      background: getCategoryColor(category),
                      display: 'inline-block',
                    }}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {category}
                  </Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: outgoing message callback */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount = 0,
  messages = [],
  sendMessage = () => undefined,
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const listRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];
    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages]);

  useEffect(() => {
    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = customEvent.detail;
      if (!payload) return;
      setStreamMessages((prev) => [...prev, payload]);
    };

    window.addEventListener('ggui:agent-data', onAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', onAgentData as EventListener);
  }, []);

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  const formatTimestamp = (ts?: string) => {
    if (!ts) return '';
    const d = new Date(ts);
    if (Number.isNaN(d.getTime())) return ts;
    return d.toLocaleString();
  };

  return (
    <Card
      padding={0}
      shadow="sm"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          <Badge variant="primary" size="sm">
            {participantCount}
          </Badge>
        </Stack>

        <Stack
          gap={varSpacing(2)}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <div ref={listRef} style={{ display: 'contents' }} />
          {groupedMessages.map((group, groupIndex) => {
            const isCurrentUser = (group.sender || '') === currentUser;
            return (
              <Stack key={`${group.sender || 'unknown'}-${groupIndex}`} gap={6} align={isCurrentUser ? 'end' : 'start'}>
                {group.items.map((msg, msgIndex) => (
                  <Stack
                    key={`${groupIndex}-${msgIndex}-${msg.timestamp || ''}`}
                    gap={4}
                    style={{
                      maxWidth: '75%',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      background: isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                      transition: 'background-color 200ms ease-in-out',
                    }}
                  >
                    <Text
                      variant="caption"
                      color={
                        isCurrentUser
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                    >
                      {msg.sender || 'Unknown'}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color={isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {msg.text || ''}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isCurrentUser
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                    >
                      {formatTimestamp(msg.timestamp)}
                    </Text>
                  </Stack>
                ))}
              </Stack>
            );
          })}
        </Stack>

        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder="Type your message..."
              value={draft}
              onChange={setDraft}
              aria-label="Compose message"
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </div>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

function varSpacing(step: number): string {
  const map: Record<number, string> = {
    1: 'var(--ggui-spacing-1, 4px)',
    2: 'var(--ggui-spacing-2, 8px)',
    4: 'var(--ggui-spacing-4, 16px)',
    6: 'var(--ggui-spacing-6, 24px)',
    8: 'var(--ggui-spacing-8, 32px)',
    12: 'var(--ggui-spacing-12, 48px)',
  };
  return map[step] || 'var(--ggui-spacing-2, 8px)';
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Alert,
  Box,
  Card,
  Container,
  Heading,
  Spinner,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isStreaming, setIsStreaming] = useState<boolean>(false);
  const [streamError, setStreamError] = useState<string | null>(null);

  const [liveAnnouncement, setLiveAnnouncement] = useState<string>('Connecting to live feed…');
  const lastEventTimeRef = useRef<number>(Date.now());

  useEffect(() => {
    setLiveStocks(stocks ?? []);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    setIsConnecting(true);

    const handler = (event: Event) => {
      try {
        const customEvent = event as CustomEvent<{
          stocks?: Props['stocks'];
          lastUpdated?: string;
        }>;
        const detail = customEvent?.detail;

        if (!detail || typeof detail !== 'object') {
          setStreamError('Live data format issue');
          return;
        }

        if (Array.isArray(detail.stocks)) {
          setLiveStocks(detail.stocks);
        }

        if (typeof detail.lastUpdated === 'string') {
          setLiveLastUpdated(detail.lastUpdated);
        }

        setIsConnecting(false);
        setIsStreaming(true);
        setStreamError(null);
        lastEventTimeRef.current = Date.now();
        setLiveAnnouncement(
          `Live update received. ${Array.isArray(detail.stocks) ? `${detail.stocks.length} stocks updated.` : 'Stock data refreshed.'}`
        );
      } catch {
        setStreamError('Live data format issue');
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);

    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  useEffect(() => {
    const intervalId = window.setInterval(() => {
      const elapsed = Date.now() - lastEventTimeRef.current;
      if (elapsed > 12000) {
        setIsStreaming(false);
        setIsConnecting(true);
        setLiveAnnouncement('Connecting to live feed…');
      }
    }, 3000);

    return () => window.clearInterval(intervalId);
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const parsed = new Date(liveLastUpdated);
    if (Number.isNaN(parsed.getTime())) return liveLastUpdated;
    return parsed.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack
        direction="vertical"
        gap="var(--ggui-spacing-6, 24px)"
        aria-label="Stock ticker dashboard"
        style={{ color: 'var(--ggui-color-onSurface, #18181b)' }}
      >
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>

          <Stack gap="var(--ggui-spacing-2, 8px)" align="end">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedUpdated}
            </Text>

            {(isConnecting || !isStreaming) && (
              <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Connecting to live feed…
                </Text>
              </Stack>
            )}
          </Stack>
        </Stack>

        <Text
          variant="caption"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          aria-live="polite"
          as="div"
        >
          {streamError ? `Live stream error: ${streamError}` : liveAnnouncement}
        </Text>

        {streamError && (
          <Alert variant="warning" title="Live feed status">
            Reconnecting… {streamError}
          </Alert>
        )}

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {liveStocks.map((stock, index) => {
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const polarity = (stock.changePercent ?? stock.change ?? 0) >= 0;
            const trendColor = polarity
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = polarity ? '▲' : '▼';

            const signedAmount =
              change > 0
                ? `+${Math.abs(change).toFixed(2)}`
                : change < 0
                ? `-${Math.abs(change).toFixed(2)}`
                : '0.00';

            const signedPercent =
              changePercent > 0
                ? `+${Math.abs(changePercent).toFixed(2)}%`
                : changePercent < 0
                ? `-${Math.abs(changePercent).toFixed(2)}%`
                : '0.00%';

            return (
              <Card
                key={stock.symbol || String(index)}
                padding="var(--ggui-spacing-4, 16px)"
                shadow="sm"
                radius="lg"
                border
                role="group"
                aria-label={`${stock.symbol || '—'} current price ${price.toFixed(2)}`}
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: trendColor,
                  transition: 'border-color 200ms ease, color 200ms ease, transform 200ms ease',
                }}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text
                      variant="body"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {stock.symbol || '—'}
                    </Text>
                    <Text as="span" variant="label" color={trendColor}>
                      {arrow}
                    </Text>
                  </Stack>

                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {stock.name || 'Unknown Company'}
                  </Text>

                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    ${price.toFixed(2)}
                  </Text>

                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                    <Text variant="label" color={trendColor}>
                      {signedAmount}
                    </Text>
                    <Text variant="label" color={trendColor}>
                      <Text as="span" variant="label" color={trendColor}>
                        {arrow}
                      </Text>{' '}
                      {signedPercent}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {liveStocks.length === 0 && !isConnecting && (
          <Card
            padding="var(--ggui-spacing-4, 16px)"
            shadow="sm"
            radius="lg"
            border
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No stock data available.
            </Text>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

export interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function resolveConditionIcon(conditionText: string): string {
  const normalized = conditionText.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('wind')) return '💨';
  return '🌤️';
}

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [
    { day: 'Day 1', icon: '☀️', high: 0, low: 0 },
    { day: 'Day 2', icon: '☁️', high: 0, low: 0 },
    { day: 'Day 3', icon: '🌧️', high: 0, low: 0 },
    { day: 'Day 4', icon: '⛈️', high: 0, low: 0 },
    { day: 'Day 5', icon: '❄️', high: 0, low: 0 },
  ],
}: Props) {
  const resolvedUnit = unit ?? 'C';
  const temperatureLabel = `${temperature}°${resolvedUnit}`;
  const humidityLabel = `${humidity}%`;
  const windLabel = `${windSpeed}`;
  const currentConditionIcon = resolveConditionIcon(condition);
  const safeForecast = forecast.slice(0, 5);

  return (
    <Card
      shadow="md"
      radius="xl"
      border
      padding={24}
      aria-label={`Weather for ${city}`}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Stack direction="horizontal" justify="between" align="start" wrap gap={16}>
          <Stack gap={4}>
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text
              variant="body"
              size="4xl"
              weight="bold"
              color="var(--ggui-color-primary-700, #0369a1)"
            >
              {temperatureLabel}
            </Text>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>

          <Box
            padding="var(--ggui-spacing-4, 16px)"
            borderRadius="var(--ggui-shape-radius-xl, 16px)"
            background="var(--ggui-color-container, #ede9fe)"
            style={{
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              minWidth: '72px',
              textAlign: 'center',
            }}
            aria-hidden="true"
          >
            <Text
              as="span"
              size="3xl"
              color="var(--ggui-color-onContainer, #4c1d95)"
            >
              {currentConditionIcon}
            </Text>
          </Box>
        </Stack>

        <Stack direction="horizontal" gap={12} wrap>
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            background="var(--ggui-color-surface, #fafafa)"
            style={{
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              flex: '1 1 160px',
            }}
          >
            <Stack gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {humidityLabel}
              </Text>
            </Stack>
          </Box>

          <Box
            padding="var(--ggui-spacing-4, 16px)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            background="var(--ggui-color-surface, #fafafa)"
            style={{
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              flex: '1 1 160px',
            }}
          >
            <Stack gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {windLabel}
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider
          margin={0}
          color="var(--ggui-color-outline, #d4d4d8)"
        />

        <Stack gap={8} aria-label="5-day forecast">
          <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Forecast
          </Text>
          <Stack direction="horizontal" gap={8} justify="between" align="stretch">
            {safeForecast.map((item, index) => {
              const displayDay = item.day ?? '—';
              const displayIcon = item.icon ?? resolveConditionIcon(condition);
              const hasHigh = typeof item.high === 'number';
              const hasLow = typeof item.low === 'number';

              return (
                <Box
                  key={`${displayDay}-${index}`}
                  padding="var(--ggui-spacing-2, 8px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  background="var(--ggui-color-surface, #fafafa)"
                  style={{
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    flex: '1 1 0',
                    minWidth: 0,
                  }}
                >
                  <Stack gap={4} align="center">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                      {displayDay}
                    </Text>
                    <Text
                      as="span"
                      size="xl"
                      color="var(--ggui-color-primary-600, #0284c7)"
                      aria-hidden="true"
                    >
                      {displayIcon}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" align="center">
                      {hasHigh || hasLow
                        ? `${hasHigh ? `${item.high}°` : '—'} / ${hasLow ? `${item.low}°` : '—'}`
                        : '— / —'}
                    </Text>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

