  ],
  title: 'Survey',
  description: 'Please complete all required steps.',
  nameLabel: 'Name',
  emailLabel: 'Email',
  commentsLabel: 'Comments',
  commentsPlaceholder: 'Share any additional feedback...',
  reviewTitle: 'Review your answers',
  nextLabel: 'Next',
  backLabel: 'Back',
  submitLabel: 'Submit Survey',
};

export default function GeneratedComponent(incomingProps: Props) {
  const props = { ...defaultProps, ...incomingProps } as Props;

  const [step, setStep] = useState(1); // 1-5 (5 is review)
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = touched.name && !name.trim() ? 'Name is required' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required'
      : touched.email && !emailRegex.test(email)
      ? 'Please enter a valid email address'
      : '';

  const stepProgressText = `Step ${Math.min(step, 4)} of 4`;
  const progressValue = (Math.min(step, 4) / 4) * 100;

  const satisfactionOptions = useMemo(
    () =>
      props.satisfactionLabels.map((label, idx) => ({
        value: String(idx + 1),
        label: `${idx + 1} - ${label}`,
      })),
    [props.satisfactionLabels]
  );

  const canGoNext = () => {
    if (step === 1) return Boolean(name.trim()) && emailRegex.test(email);
    if (step === 2) return Boolean(satisfaction);
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    return false;
  };

  const handleToggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((f) => f !== feature)
    );
  };

  const handleSubmit = async () => {
    if (!props.submit) return;
    setIsSubmitting(true);
    setFeedback(null);
    try {
      await props.submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: {
          value: satisfaction,
          label: props.satisfactionLabels[Number(satisfaction) - 1] ?? '',
        },
        featureInterests,
        comments: comments.trim(),
      });
      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch {
      setFeedback({ type: 'error', message: 'Submission failed. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={
        {
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          color: 'var(--ggui-color-onSurface, #18181b)',
          maxWidth: '720px',
          margin: '0 auto',
        } as React.CSSProperties
      }
    >
      <Stack gap={16}>
        <Stack gap={6}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {stepProgressText}
          </Text>
          <Progress value={progressValue} max={100} size="md" />
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {props.title}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {props.description}
          </Text>
        </Stack>

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label={props.nameLabel || 'Name'}
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder={props.nameLabel || 'Name'}
              onBlur={() => setTouched((t) => ({ ...t, name: true }))}
              aria-label={props.nameLabel || 'Name'}
            />
            <Input
              label={props.emailLabel || 'Email'}
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              placeholder="you@example.com"
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              aria-label={props.emailLabel || 'Email'}
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you?"
            value={satisfaction}
            onChange={setSatisfaction}
            options={satisfactionOptions}
            direction="vertical"
          />
        )}

        {step === 3 && (
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Feature interests
            </Text>
            {props.featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={featureInterests.includes(feature)}
                onChange={(checked) => handleToggleFeature(feature, checked)}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label={props.commentsLabel || 'Comments'}
            value={comments}
            onChange={setComments}
            placeholder={props.commentsPlaceholder}
            rows={6}
            maxLength={500}
            showCount
            helperText="Optional"
            aria-label={props.commentsLabel || 'Comments'}
          />
        )}

        {step === 5 && (
          <Stack gap={10}>
            <Text variant="bodyLarge" weight="semibold">
              {props.reviewTitle}
            </Text>
            <Card
              padding={16}
              radius="md"
              border
              shadow="none"
              style={
                {
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                } as React.CSSProperties
              }
            >
              <Stack gap={8}>
                <Text variant="bodySmall"><strong>Name:</strong> {name || '-'}</Text>
                <Text variant="bodySmall"><strong>Email:</strong> {email || '-'}</Text>
                <Text variant="bodySmall">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfaction
                    ? `${satisfaction} - ${props.satisfactionLabels[Number(satisfaction) - 1] ?? ''}`
                    : '-'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Feature interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : '-'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Comments:</strong> {comments.trim() || '-'}
                </Text>
              </Stack>
            </Card>

            {feedback && (
              <Text
                variant="bodySmall"
                color={
                  feedback.type === 'success'
                    ? 'var(--ggui-color-success-600, #16a34a)'
                    : 'var(--ggui-color-error-600, #dc2626)'
                }
              >
                {feedback.message}
              </Text>
            )}
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button
            variant="ghost"
            onClick={() => setStep((s) => Math.max(1, s - 1))}
            disabled={step === 1 || isSubmitting}
          >
            {props.backLabel}
          </Button>

          {step < 5 ? (
            <Button
              variant="primary"
              onClick={() => {
                if (step === 1) setTouched({ name: true, email: true });
                if (canGoNext()) setStep((s) => Math.min(5, s + 1));
              }}
              disabled={!canGoNext() || isSubmitting}
            >
              {step === 4 ? 'Review' : props.nextLabel}
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={isSubmitting}
              disabled={isSubmitting}
            >
              {props.submitLabel}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

GeneratedComponent.defaultProps = defaultProps;

