import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = '',
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connectionState, setConnectionState] = useState<'connecting' | 'live'>('connecting');

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    setConnectionState('connecting');

    const timer = window.setTimeout(() => {
      setConnectionState('live');
    }, 1200);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
      }>;

      const payload = customEvent.detail;
      if (!payload) return;

      if (Array.isArray(payload.stocks)) {
        setLiveStocks(payload.stocks);
      }
      if (typeof payload.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      }
      setConnectionState('live');
    };

    window.addEventListener('ggui:agent-data', handleAgentData);

    return () => {
      window.clearTimeout(timer);
      window.removeEventListener('ggui:agent-data', handleAgentData);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  const hasStocks = liveStocks.length > 0;

  return (
    <Stack
      gap={16}
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Card
        padding={16}
        shadow="sm"
        radius="lg"
        border
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-label="Dashboard title"
          >
            Market Watch
          </Text>
          <Stack direction="horizontal" gap={8} align="center">
            {connectionState === 'connecting' ? (
              <>
                <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Connecting…
                </Text>
              </>
            ) : (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Live
              </Text>
            )}
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedUpdated}
            </Text>
          </Stack>
        </Stack>
      </Card>

      {!hasStocks ? (
        <Card
          padding={24}
          shadow="none"
          border
          radius="lg"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack align="center" gap={8}>
            {connectionState === 'connecting' && (
              <Spinner size={20} color="var(--ggui-color-primary-600, #0284c7)" />
            )}
            <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {connectionState === 'connecting' ? 'Loading live stock data…' : 'No stocks available.'}
            </Text>
          </Stack>
        </Card>
      ) : (
        <Stack
          gap={16}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
          }}
        >
          {liveStocks.map((stock, index) => {
            const symbol = stock.symbol ?? '—';
            const name = stock.name ?? 'Unknown Company';
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;

            const positive = change >= 0;
            const trendColor = positive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = positive ? '▲' : '▼';

            return (
              <Card
                key={`${symbol}-${name}-${index}`}
                padding={16}
                shadow="sm"
                border
                radius="lg"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: trendColor,
                  transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                }}
                aria-label={`Stock card for ${symbol}`}
              >
                <Stack gap={8}>
                  <Text as="div" size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {symbol}
                  </Text>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                    {name}
                  </Text>
                  <Text as="div" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    ${price.toFixed(2)}
                  </Text>
                  <Text as="div" variant="bodySmall" color={trendColor} weight="medium">
                    {change >= 0 ? '+' : ''}
                    {change.toFixed(2)}
                  </Text>
                  <Text as="div" variant="bodySmall" color={trendColor} weight="semibold" aria-live="polite">
                    {arrow} {changePercent >= 0 ? '+' : ''}
                    {changePercent.toFixed(2)}%
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Stack>
      )}
    </Stack>
  );
}

