  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailValid = emailRegex.test(email.trim());
  const nameValid = name.trim().length > 0;

  const canNextStep1 = nameValid && emailValid && avatar.length > 0;
  const canNextStep2 = role.trim().length > 0;

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const handleNext = () => {
    if (step === 1 && !canNextStep1) return;
    if (step === 2 && !canNextStep2) return;
    setStep((s) => Math.min(3, s + 1));
  };

  const handleBack = () => setStep((s) => Math.max(1, s - 1));

  const handleComplete = () => {
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          color: 'var(--ggui-color-onSurface, #18181b)',
          maxWidth: '640px',
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-live="polite"
            >
              Step {step} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          <Stack
            gap={16}
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold">
                  Profile Setup
                </Text>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={!nameValid && name.length > 0 ? 'Name is required' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="Enter your email"
                  error={
                    email.length > 0 && !emailValid
                      ? 'Please enter a valid email address'
                      : undefined
                  }
                />
                <Stack gap={8}>
                  <Text variant="label" as="label">
                    Avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {props.avatarOptions.slice(0, 4).map((option) => {
                      const selected = avatar === option;
                      return (
                        <Button
                          key={option}
                          variant={selected ? 'primary' : 'outline'}
                          size="md"
                          aria-label={`Select avatar ${option}`}
                          onClick={() => setAvatar(option)}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold">
                  Preferences
                </Text>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select role"
                  required
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  error={role.length === 0 ? 'Role is required' : undefined}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label={`Theme preference: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold">
                  Review & Confirm
                </Text>
                <Card
                  padding={16}
                  border
                  shadow="none"
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text variant="bodySmall">
                      <strong>Name:</strong> {name || '-'}
                    </Text>
                    <Text variant="bodySmall">
                      <strong>Email:</strong> {email || '-'}
                    </Text>
                    <Text variant="bodySmall">
                      <strong>Avatar:</strong> {avatar || '-'}
                    </Text>
                    <Text variant="bodySmall">
                      <strong>Role:</strong> {role || '-'}
                    </Text>
                    <Text variant="bodySmall">
                      <strong>Email Notifications:</strong>{' '}
                      {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="bodySmall">
                      <strong>Theme:</strong> {theme}
                    </Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between" gap={8}>
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={(step === 1 && !canNextStep1) || (step === 2 && !canNextStep2)}
              >
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="secondary" onClick={() => setStep(2)}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete}>
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
      {/* __GGUI_META__ {"category":"Form","description":"Three-step onboarding wizard with validation, progress indicator, review, and completion callback."} */}
    </>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  submit?: (answers: {
    name: string;
    email: string;
    satisfaction: string;
    featureInterests: string[];
    comments: string;
  }) => void | Promise<void>;

  /** Optional template defaults */
  title?: string;
  subtitle?: string;
  nameLabel?: string;
  emailLabel?: string;
  commentsLabel?: string;
  reviewTitle?: string;
  submitLabel?: string;
  backLabel?: string;
  nextLabel?: string;
  submittingLabel?: string;
  successMessage?: string;
  errorMessage?: string;
  initialName?: string;
  initialEmail?: string;
  initialSatisfaction?: string;
  initialFeatureInterests?: string[];
  initialComments?: string;
}

export default function GeneratedComponent({
  featureOptions = ['Performance', 'Analytics', 'Integrations'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  submit,
  title = 'Customer Survey',
  subtitle = 'Please complete all required fields before submitting.',
  nameLabel = 'Name',
  emailLabel = 'Email',
  commentsLabel = 'Additional Comments',
  reviewTitle = 'Review Your Responses',
  submitLabel = 'Submit Survey',
  backLabel = 'Back',
  nextLabel = 'Next',
  submittingLabel = 'Submitting...',
  successMessage = 'Survey submitted successfully.',
  errorMessage = 'Something went wrong. Please try again.',
  initialName = '',
  initialEmail = '',
  initialSatisfaction = '',
  initialFeatureInterests = [],
  initialComments = '',
}: Props) {
  const totalSteps = 5;
  const [step, setStep] = useState(1);

  const [name, setName] = useState(initialName);
  const [email, setEmail] = useState(initialEmail);
  const [satisfaction, setSatisfaction] = useState(initialSatisfaction);
  const [featureInterests, setFeatureInterests] = useState<string[]>(initialFeatureInterests);
  const [comments, setComments] = useState(initialComments);

  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [satisfactionTouched, setSatisfactionTouched] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const nameError = nameTouched && !name.trim() ? `${nameLabel} is required` : '';
  const emailError =
    emailTouched && !email.trim()
      ? `${emailLabel} is required`
      : emailTouched && !emailValid
      ? 'Please enter a valid email address'
      : '';

  const satisfactionError =
    satisfactionTouched && !satisfaction ? 'Please choose a satisfaction rating' : '';

  const isStepValid = useMemo(() => {
    if (step === 1) return name.trim().length > 0 && emailValid;
    if (step === 2) return satisfaction.length > 0;
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    if (step === 5) return true;
    return false;
  }, [step, name, emailValid, satisfaction, comments.length]);

  const satisfactionOptions = useMemo(
    () =>
      satisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [satisfactionLabels]
  );

  const onNext = () => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
    }
    if (step === 2) setSatisfactionTouched(true);

    if (!isStepValid) return;
    setStep((s) => Math.min(totalSteps, s + 1));
    setStatus('idle');
  };

  const onBack = () => {
    setStep((s) => Math.max(1, s - 1));
    setStatus('idle');
  };

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const handleSubmit = async () => {
    if (!submit) return;
    setIsSubmitting(true);
    setStatus('idle');
    try {
      await submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction,
        featureInterests,
        comments,
      });
      setStatus('success');
    } catch {
      setStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
    >
      <Stack gap={16}>
        <Stack gap={6}>
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {subtitle}
          </Text>
        </Stack>

        <Stack gap={6}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={step} max={totalSteps} size="md" />
        </Stack>

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label={nameLabel}
              required
              value={name}
              onChange={setName}
              onBlur={() => setNameTouched(true)}
              error={nameError || undefined}
              placeholder="Enter your name"
              aria-label={nameLabel}
            />
            <Input
              label={emailLabel}
              required
              type="email"
              value={email}
              onChange={setEmail}
              onBlur={() => setEmailTouched(true)}
              error={emailError || undefined}
              placeholder="Enter your email"
              aria-label={emailLabel}
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you?"
            value={satisfaction}
            onChange={setSatisfaction}
            options={satisfactionOptions}
            error={satisfactionError || undefined}
          />
        )}

        {step === 3 && (
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Which features are you interested in?
            </Text>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={featureInterests.includes(feature)}
                onChange={(checked) => toggleFeature(feature, checked)}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label={commentsLabel}
            value={comments}
            onChange={setComments}
            rows={5}
            maxLength={500}
            showCount
            helperText="Optional"
            placeholder="Share your thoughts..."
            aria-label={commentsLabel}
          />
        )}

        {step === 5 && (
          <Stack gap={10}>
            <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {reviewTitle}
            </Text>
            <Card
              padding={16}
              border
              shadow="none"
              radius="md"
            >
              <Stack gap={8}>
                <Text variant="bodySmall"><strong>{nameLabel}:</strong> {name || '-'}</Text>
                <Text variant="bodySmall"><strong>{emailLabel}:</strong> {email || '-'}</Text>
                <Text variant="bodySmall">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfaction
                    ? `${satisfaction} - ${satisfactionLabels[Number(satisfaction) - 1] ?? ''}`
                    : '-'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Feature Interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : '-'}
                </Text>
                <Text variant="bodySmall">
                  <strong>{commentsLabel}:</strong> {comments || '-'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        {status === 'success' && <Alert variant="success">{successMessage}</Alert>}
        {status === 'error' && <Alert variant="error">{errorMessage}</Alert>}

        <Stack direction="horizontal" justify="between" gap={8}>
          <Button variant="ghost" onClick={onBack} disabled={step === 1 || isSubmitting}>
            {backLabel}
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              onClick={onNext}
              disabled={!isStepValid || isSubmitting}
            >
              {nextLabel}
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              disabled={isSubmitting}
              loading={isSubmitting}
            >
              {isSubmitting ? submittingLabel : submitLabel}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColorMap: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-warning-500, #f59e0b)',
    'alkaline earth metal': 'var(--ggui-color-warning-600, #d97706)',
    'transition metal': 'var(--ggui-color-primary-600, #0284c7)',
    'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
    metalloid: 'var(--ggui-color-success-500, #22c55e)',
    nonmetal: 'var(--ggui-color-success-600, #16a34a)',
    halogen: 'var(--ggui-color-error-500, #ef4444)',
    'noble gas': 'var(--ggui-color-primary-500, #0ea5e9)',
    lanthanide: 'var(--ggui-color-primary-700, #0369a1)',
    actinide: 'var(--ggui-color-error-600, #dc2626)',
    unknown: 'var(--ggui-color-neutral-500, #6b7280)',
  };

  const normalizedElements = useMemo(
    () =>
      elements.map((el) => ({
        atomicNumber: el.atomicNumber ?? 0,
        symbol: el.symbol ?? '',
        name: el.name ?? '',
        atomicWeight: el.atomicWeight,
        category: (el.category ?? 'unknown').toLowerCase(),
        row: el.row ?? 1,
        col: el.col ?? 1,
      })),
    [elements]
  );

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return normalizedElements;
    return normalizedElements.filter(
      (el) =>
        el.name.toLowerCase().includes(q) || el.symbol.toLowerCase().includes(q)
    );
  }, [normalizedElements, query]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return null;
    return normalizedElements.find((el) => el.atomicNumber === selectedAtomicNumber) ?? null;
  }, [normalizedElements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    normalizedElements.forEach((el) => set.add(el.category || 'unknown'));
    return Array.from(set);
  }, [normalizedElements]);

  return (
    <Stack gap={16}>
      <Card
        padding={16}
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack gap={12}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Periodic Table of Elements
          </Text>

          <Input
            label="Search elements"
            type="search"
            placeholder="Search by name or symbol"
            value={query}
            onChange={setQuery}
            helperText="Type to filter elements"
          />

          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            {filteredElements.map((el) => {
              const color =
                categoryColorMap[el.category] || 'var(--ggui-color-neutral-400, #9ca3af)';
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

              return (
                <button
                  key={`${el.atomicNumber}-${el.symbol}`}
                  type="button"
                  role="gridcell"
                  aria-label={`${el.name} (${el.symbol})`}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    minHeight: 56,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    border: `1px solid ${isSelected ? 'var(--ggui-color-onSurface, #18181b)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                    background: 'var(--ggui-color-surface, #fafafa)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    position: 'relative',
                    cursor: 'pointer',
                    transition: 'transform 150ms ease, box-shadow 150ms ease, border-color 150ms ease',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                    outline: 'none',
                  }}
                  onFocus={(e) => {
                    e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
                    e.currentTarget.style.outlineOffset = '2px';
                  }}
                  onBlur={(e) => {
                    e.currentTarget.style.outline = 'none';
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.transform = 'translateY(-1px)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.transform = 'translateY(0)';
                  }}
                >
                  <span
                    aria-hidden="true"
                    style={{
                      position: 'absolute',
                      top: 4,
                      left: 6,
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      fontWeight: 'var(--ggui-font-weight-medium, 500)',
                    }}
                  >
                    {el.atomicNumber || ''}
                  </span>
                  <span
                    aria-hidden="true"
                    style={{
                      display: 'block',
                      fontSize: 'var(--ggui-font-size-lg, 18px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      textAlign: 'center',
                      lineHeight: '56px',
                    }}
                  >
                    {el.symbol}
                  </span>
                  <span
                    aria-hidden="true"
                    style={{
                      position: 'absolute',
                      bottom: 0,
                      left: 0,
                      right: 0,
                      height: 4,
                      background: color,
                      borderBottomLeftRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      borderBottomRightRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    }}
                  />
                </button>
              );
            })}
          </div>

          <Card
            padding={12}
            shadow="none"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Stack gap={6}>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Element Details
              </Text>
              {selectedElement ? (
                <>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Name: {selectedElement.name}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Symbol: {selectedElement.symbol}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Atomic Number: {selectedElement.atomicNumber}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Atomic Weight: {selectedElement.atomicWeight ?? '—'}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                    Category: {selectedElement.category}
                  </Text>
                </>
              ) : (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Select an element to view details.
                </Text>
              )}
            </Stack>
          </Card>

          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" gap={8} wrap>
              {categories.map((category) => {
                const color =
                  categoryColorMap[category] || 'var(--ggui-color-neutral-400, #9ca3af)';
                return (
                  <Card
                    key={category}
                    padding="6px 10px"
                    radius="md"
                    shadow="none"
                    style={{
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      background: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <Stack direction="horizontal" gap={6} align="center">
                      <span
                        aria-hidden="true"
                        style={{
                          width: 10,
                          height: 10,
                          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                          background: color,
                          display: 'inline-block',
                        }}
                      />
                      <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                        {category}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Stack>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type MessageItem = { sender?: string; text?: string; timestamp?: string };

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount,
  messages = [],
  sendMessage,
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<MessageItem[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: MessageItem[] }> = [];
    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<MessageItem | { message?: MessageItem }>;
      const detail = customEvent.detail;
      const incoming = (detail as { message?: MessageItem })?.message ?? (detail as MessageItem);

      if (incoming && (incoming.text || incoming.sender || incoming.timestamp)) {
        setStreamMessages((prev) => [...prev, incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const onSubmit = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setDraft('');
  };

  return (
    <Card
      padding={0}
      radius="lg"
      border
      shadow="sm"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm">
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Box
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          ref={scrollRef}
          aria-live="polite"
          aria-label="Chat messages"
        >
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {groupedMessages.map((group, groupIndex) => {
              const isCurrentUser = (group.sender || '') === currentUser;
              return (
                <Stack
                  key={`${group.sender || 'unknown'}-${groupIndex}`}
                  align={isCurrentUser ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {group.sender || 'Unknown'}
                  </Text>

                  <Stack gap="var(--ggui-spacing-1, 4px)" align={isCurrentUser ? 'end' : 'start'}>
                    {group.items.map((msg, msgIndex) => (
                      <Box
                        key={`${groupIndex}-${msgIndex}-${msg.timestamp || ''}`}
                        padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                        borderRadius="var(--ggui-shape-radius-lg, 12px)"
                        style={{
                          maxWidth: '80%',
                          background: isCurrentUser
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                          color: isCurrentUser
                            ? 'var(--ggui-color-surface, #fafafa)'
                            : 'var(--ggui-color-onSurface, #18181b)',
                          transition:
                            'background-color 200ms ease-in-out, color 200ms ease-in-out',
                        }}
                      >
                        <Stack gap="var(--ggui-spacing-1, 4px)">
                          <Text
                            variant="bodySmall"
                            color={
                              isCurrentUser
                                ? 'var(--ggui-color-surface, #fafafa)'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                          >
                            {msg.text || ''}
                          </Text>
                          <Text
                            variant="caption"
                            color={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                            align={isCurrentUser ? 'right' : 'left'}
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Box style={{ flex: 1 }}>
            <Input
              label=""
              value={draft}
              onChange={setDraft}
              placeholder="Type your message..."
              aria-label="Compose message"
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  onSubmit();
                }
              }}
            />
          </Box>
          <Button
            variant="primary"
            onClick={onSubmit}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner, Container } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type AgentDataPayload = {
  stocks?: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  lastUpdated?: string;
};

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = '',
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(stocks.length === 0);

  useEffect(() => {
    setLiveStocks(stocks);
    setLiveLastUpdated(lastUpdated);
    setIsLoading(stocks.length === 0);
  }, [stocks, lastUpdated]);

  useEffect(() => {
    let connectionTimer: number | undefined;

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<AgentDataPayload>;
      const payload = customEvent.detail ?? {};

      if (payload.stocks) {
        setLiveStocks(payload.stocks);
      }
      if (payload.lastUpdated) {
        setLiveLastUpdated(payload.lastUpdated);
      }

      setIsLoading(false);
      setIsConnecting(false);
    };

    connectionTimer = window.setTimeout(() => {
      setIsConnecting(false);
    }, 1500);

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);

    return () => {
      if (connectionTimer) window.clearTimeout(connectionTimer);
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  const formattedUpdatedTime = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          wrap
        >
          <Text
            as="div"
            size="3xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            {(isConnecting || isLoading) && (
              <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
            )}
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {isConnecting ? 'Connecting to live feed…' : isLoading ? 'Loading prices…' : `Last Updated: ${formattedUpdatedTime}`}
            </Text>
          </Stack>
        </Stack>

        <div
          style={{
            display: 'grid',
            gap: 'var(--ggui-spacing-4, 16px)',
            gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
          }}
          aria-live="polite"
          aria-busy={isLoading || isConnecting}
        >
          {liveStocks.map((stock, index) => {
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const isPositive = change >= 0;
            const trendColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = isPositive ? '▲' : '▼';

            return (
              <Card
                key={`${stock.symbol ?? 'stock'}-${index}`}
                padding="var(--ggui-spacing-4, 16px)"
                shadow="sm"
                radius="lg"
                border
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text
                    as="div"
                    size="3xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {stock.symbol ?? '—'}
                  </Text>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    truncate
                  >
                    {stock.name ?? 'Unknown Company'}
                  </Text>
                  <Text
                    as="div"
                    size="xl"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text
                      variant="label"
                      color={trendColor}
                    >
                      {change >= 0 ? '+' : ''}
                      {change.toFixed(2)}
                    </Text>
                    <Text
                      variant="label"
                      color={trendColor}
                    >
                      {arrow} {changePercent >= 0 ? '+' : ''}
                      {changePercent.toFixed(2)}%
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

const isEmailValid = (value: string): boolean => {
  if (!value.trim()) return false;
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
};

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<number>(1);

  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const step1NameError = name.trim() ? '' : 'Name is required';
  const step1EmailError = email.trim()
    ? isEmailValid(email)
      ? ''
      : 'Please enter a valid email address'
    : 'Email is required';

  const step1Valid = !step1NameError && !step1EmailError && !!avatar;
  const step2Valid = !!role;
  const canGoNext = currentStep === 1 ? step1Valid : currentStep === 2 ? step2Valid : true;

  const progressValue = useMemo(() => (currentStep / 3) * 100, [currentStep]);

  const handleNext = () => {
    if (!canGoNext) return;
    setCurrentStep((prev) => Math.min(3, prev + 1));
  };

  const handleBack = () => {
    setCurrentStep((prev) => Math.max(1, prev - 1));
  };

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  const roleOptions = props.roleOptions.map((item) => ({ value: item, label: item }));

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <MotionKeyframes />
      <Stack gap={20}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {currentStep} of 3
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        <Stack
          gap={16}
          style={{
            animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
          }}
        >
          {currentStep === 1 && (
            <Stack gap={16}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Profile Setup
              </Text>

              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                placeholder="Enter your name"
                error={name.length > 0 || !step1NameError ? undefined : step1NameError}
              />

              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                placeholder="you@example.com"
                error={email.length > 0 ? step1EmailError || undefined : undefined}
                helperText={email.length === 0 ? 'Enter a valid email address' : undefined}
              />

              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Select Avatar
                </Text>
                <Stack direction="horizontal" gap={8} wrap>
                  {props.avatarOptions.map((option) => {
                    const selected = option === avatar;
                    return (
                      <Button
                        key={option}
                        variant={selected ? 'primary' : 'outline'}
                        size="md"
                        onClick={() => setAvatar(option)}
                        aria-label={`Select avatar ${option}`}
                      >
                        {option}
                      </Button>
                    );
                  })}
                </Stack>
              </Stack>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap={16}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Preferences
              </Text>

              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={roleOptions}
                placeholder="Select role"
                required
                error={role ? undefined : 'Role is required'}
              />

              <Toggle
                label="Email notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
                size="md"
              />

              <Toggle
                label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                checked={theme === 'dark'}
                onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                size="md"
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap={12}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Review & Confirm
              </Text>
              <Card
                padding={16}
                shadow="none"
                radius="md"
                border
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Stack gap={8}>
                  <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                  <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                  <Text variant="body"><strong>Avatar:</strong> {avatar || '-'}</Text>
                  <Text variant="body"><strong>Role:</strong> {role || '-'}</Text>
                  <Text variant="body">
                    <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                  </Text>
                  <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Stack>

        <Stack direction="horizontal" justify="between" align="center">
          <Button
            variant="ghost"
            size="md"
            onClick={handleBack}
            disabled={currentStep === 1}
            aria-label="Go back"
          >
            Back
          </Button>

          {currentStep < 3 ? (
            <Button
              variant="primary"
              size="md"
              onClick={handleNext}
              disabled={!canGoNext}
              aria-label="Next step"
            >
              Next
            </Button>
          ) : (
            <Stack direction="horizontal" gap={8}>
              <Button variant="outline" size="md" onClick={handleBack} aria-label="Go back to edit">
                Go Back
              </Button>
              <Button variant="primary" size="md" onClick={handleComplete} aria-label="Complete setup">
                Complete Setup
              </Button>
            </Stack>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Divider, 
  Box, 
  Badge 
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * Displays current weather information and a 5-day forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  // Ensure unit displays correctly
  const unitSuffix = unit.startsWith('°') ? unit : `°${unit}`;

  // Helper to map conditions to simple emojis for visualization
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm')) return '⚡';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Card 
      shadow="md" 
      padding={24} 
      radius="xl"
      border
      style={{
        maxWidth: '480px',
        width: '100%',
        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
      }}
    >
      <Stack gap={24}>
        {/* Top Section: City and Status Badge */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text 
              variant="bodySmall" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Current Conditions
            </Text>
          </Stack>
          <Badge variant="primary" size="lg">
            {condition}
          </Badge>
        </Stack>

        {/* Main Temperature Display */}
        <Stack direction="horizontal" justify="center" align="center" gap={32}>
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-onSurface, #18181b)"
            style={{ fontSize: 'var(--ggui-font-size-4xl, 64px)', lineHeight: 1 }}
          >
            {temperature}{unitSuffix}
          </Text>
          <Text 
            style={{ fontSize: '48px' }}
          >
            {getConditionEmoji(condition)}
          </Text>
        </Stack>

        {/* Weather Metrics */}
        <Box 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          padding={16} 
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" justify="around">
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
            </Stack>

            <Divider orientation="vertical" margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={4} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Grid */}
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Stack 
              key={item.day || index} 
              align="center" 
              gap={12} 
              style={{ flex: 1 }}
            >
              <Text 
                variant="overline" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {item.day}
              </Text>
              <Text style={{ fontSize: '24px' }}>
                {item.icon || '☀️'}
              </Text>
              <Stack gap={0} align="center">
                <Text weight="bold" size="sm" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Divider,
  Container,
  Box,
  Badge,
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Callback to submit the survey results */
  onSubmit: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

/**
 * A multi-step survey form component.
 */
export default function SurveyForm(props: Props) {
  const { featureOptions = [], satisfactionLabels = [], onSubmit } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const validateEmail = (e: string) => /\S+@\S+\.\S+/.test(e);
  const isS1V = formData.name.trim().length > 0 && validateEmail(formData.email);
  const isS2V = formData.satisfaction !== '';

  const progress = step > 4 ? 100 : (step / 4) * 100;

  return (
    <Container maxWidth="md" padding={20}>
      <Stack gap={24}>
        <Stack gap={12}>
          <Progress value={progress} variant="default" size="md" />
          <Text variant="caption">Progress {Math.round(progress)}%</Text>
        </Stack>

        <Card padding={32} shadow="md" radius="xl" border>
          <Stack gap={32}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Step 1: Contact</Heading>
                <Input label="Name" value={formData.name} onChange={(v: string) => setFormData({ ...formData, name: v })} />
                <Input label="Email" type="email" value={formData.email} onChange={(v: string) => setFormData({ ...formData, email: v })} />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Step 2: Satisfaction</Heading>
                <RadioGroup
                  label="Rate us"
                  value={formData.satisfaction}
                  onChange={(v: string) => setFormData({ ...formData, satisfaction: v })}
                  options={satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: l }))}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Step 3: Features</Heading>
                <Stack gap={12}>
                  {featureOptions.map(f => (
                    <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={(c: boolean) => setFormData(p => ({ ...p, features: c ? [...p.features, f] : p.features.filter(x => x !== f) }))} />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24}>
                <Heading level={3}>Step 4: Feedback</Heading>
                <TextArea
                  label="Comments"
                  value={formData.comments}
                  onChange={(v: string) => setFormData({ ...formData, comments: v })}
                  maxLength={500}
                  showCount={true}
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24}>
                <Heading level={3}>Summary</Heading>
                <Card padding={16} border>
                  <Stack gap={8}>
                    <Text variant="body">Name: {formData.name}</Text>
                    <Text variant="body">Email: {formData.email}</Text>
                    <Text variant="body">Rating: {formData.satisfaction}</Text>
                    <Text variant="body">Features: {formData.features.join(', ')}</Text>
                    <Text variant="body">Comments: {formData.comments}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Stack direction="horizontal" justify="between">
              <Button variant="ghost" onClick={() => setStep(s => s - 1)} disabled={step === 1}>Back</Button>
              {step < 5 ? (
                <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={step === 1 ? !isS1V : (step === 2 ? !isS2V : false)}>Next</Button>
              ) : (
                <Button variant="primary" onClick={() => onSubmit(formData)} fullWidth>Submit</Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import { useState, useMemo } from 'react';
import { 
  Container, 
  Stack, 
  Text, 
  Card, 
  Box, 
  Badge,
  Heading,
  Divider,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to theme color tokens.
 */
const getCategoryColor = (category?: string) => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info-100, #cffafe)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-neutral-100, #f3f4f6)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-200, #e5e7eb)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-50, #f0f9ff)';
  if (cat.includes('actinide')) return 'var(--ggui-color-error-50, #fef2f2)';
  return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

const getCategoryTextColor = (category?: string) => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-700, #0369a1)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-700, #b91c1c)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-700, #b45309)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info-700, #0e7490)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-700, #15803d)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-neutral-700, #374151)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-800, #1f2937)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-800, #075985)';
  if (cat.includes('actinide')) return 'var(--ggui-color-error-800, #991b1b)';
  return 'var(--ggui-color-onSurfaceVariant, #52525b)';
};

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const term = search.toLowerCase();
    return elements.filter(el => 
      el.name?.toLowerCase().includes(term) || 
      el.symbol?.toLowerCase().includes(term)
    );
  }, [elements, search]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach(el => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set);
  }, [elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header and Search */}
        <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-4, 16px)">
          <Heading level={2}>Periodic Table</Heading>
          <Box borderRadius="var(--ggui-shape-radius-md, 8px)" style={{ width: '300px' }}>
             <SearchField 
              value={search} 
              onChange={setSearch} 
              placeholder="Filter by name or symbol..." 
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Box 
          padding="var(--ggui-spacing-3, 12px)" 
          borderRadius="var(--ggui-shape-radius-lg, 12px)" 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" wrap align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Categories:</Text>
            {categories.map((cat) => (
              <Badge 
                key={cat} 
                pill={false}
                size="sm"
                style={{ 
                  backgroundColor: getCategoryColor(cat),
                  color: getCategoryTextColor(cat),
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
                }}
              >
                {cat}
              </Badge>
            ))}
          </Stack>
        </Box>

        {/* Periodic Table Grid Container */}
        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(64px, 1fr))',
            gridTemplateRows: 'repeat(10, minmax(64px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            minWidth: '1152px'
          }}>
            {elements.map((el) => {
              const isFiltered = filteredElements.some(f => f.atomicNumber === el.atomicNumber);
              const isSelected = selected?.atomicNumber === el.atomicNumber;

              return (
                <button
                  key={el.atomicNumber}
                  onClick={() => setSelected(el)}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    border: isSelected 
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    backgroundColor: getCategoryColor(el.category),
                    opacity: isFiltered ? 1 : 0.2,
                    cursor: 'pointer',
                    transition: 'transform 150ms ease-in-out, box-shadow 150ms ease-in-out',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                    outline: 'none',
                    transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1
                  }}
                  aria-label={`${el.name} (${el.symbol})`}
                >
                  <div style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)' }}>
                    <Text 
                      variant="caption" 
                      style={{ 
                        fontSize: '10px',
                        color: getCategoryTextColor(el.category),
                        lineHeight: 1
                      }}
                    >
                      {el.atomicNumber}
                    </Text>
                  </div>
                  <Text 
                    variant="bodyLarge" 
                    weight="bold"
                    style={{ 
                      color: getCategoryTextColor(el.category),
                      lineHeight: 1
                    }}
                  >
                    {el.symbol}
                  </Text>
                  <Text 
                    variant="caption" 
                    truncate
                    style={{ 
                      fontSize: '9px',
                      color: getCategoryTextColor(el.category),
                      marginTop: 'var(--ggui-spacing-1, 4px)'
                    }}
                  >
                    {el.name}
                  </Text>
                </button>
              );
            })}
          </div>
        </Box>

        {/* Detail Panel */}
        {selected && (
          <div style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Stack direction="horizontal" align="center" justify="between" wrap gap="var(--ggui-spacing-4, 16px)">
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={2}>{selected.name}</Heading>
                    <Badge 
                      style={{ 
                        backgroundColor: getCategoryColor(selected.category),
                        color: getCategoryTextColor(selected.category)
                      }}
                    >
                      {selected.category}
                    </Badge>
                  </Stack>
                  <Box 
                    background={getCategoryColor(selected.category)} 
                    borderRadius="var(--ggui-shape-radius-lg, 12px)" 
                    padding="var(--ggui-spacing-5, 20px)"
                    style={{ minWidth: '80px', textAlign: 'center' }}
                  >
                    <Text size="4xl" weight="bold" color={getCategoryTextColor(selected.category)}>
                      {selected.symbol}
                    </Text>
                  </Box>
                </Stack>

                <Divider margin="var(--ggui-spacing-2, 8px)" />

                <div style={{ 
                  display: 'grid', 
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: 'var(--ggui-spacing-6, 24px)'
                }}>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                    <Text variant="bodyLarge" weight="semibold">{selected.atomicNumber}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="semibold">{selected.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <Text variant="bodyLarge" weight="semibold">{selected.category}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Position</Text>
                    <Text variant="bodyLarge" weight="semibold">Period {selected.row}, Group {selected.col}</Text>
                  </Stack>
                </div>
              </Stack>
            </Card>
          </div>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Box,
  Badge,
  Heading,
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title = 'Chat', currentUser = 'You', participantCount = 0, messages = [], sendMessage } = props;
  const [val, setVal] = useState('');
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (ref.current) ref.current.scrollTop = ref.current.scrollHeight;
  }, [messages]);

  const send = () => {
    if (!val.trim()) return;
    sendMessage({ text: val, timestamp: new Date().toISOString() });
    setVal('');
  };

  const onKd = (e: any) => { if (e.key === 'Enter') send(); };

  const LabelText = Text as any;

  return (
    <Card padding="0" shadow="md" radius="lg" border style={{ display: 'flex', flexDirection: 'column', height: '600px', width: '100%', backgroundColor: 'var(--ggui-color-surface, #ffffff)', overflow: 'hidden' }}>
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outline, #e5e7eb)' }}>
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={4}>{title}</Heading>
          {participantCount > 0 && <Badge variant="primary" size="sm" pill>{participantCount}</Badge>}
        </Stack>
      </Box>

      <Box style={{ flex: 1, overflowY: 'auto', backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)' }}>
        <div ref={ref}>
          <Stack gap="var(--ggui-spacing-3, 12px)">
            {messages.map((m, i) => {
              const isMe = m.sender === currentUser;
              return (
                <Stack key={i} align={isMe ? 'end' : 'start'} gap="var(--ggui-spacing-1, 4px)">
                  {m.sender !== currentUser && <Text variant="label" size="xs">{m.sender}</Text>}
                  <Box padding="var(--ggui-spacing-2, 8px)" style={{ borderRadius: 'var(--ggui-shape-radius-md, 8px)', backgroundColor: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'white', color: isMe ? 'white' : 'black', border: isMe ? 'none' : '1px solid var(--ggui-color-outline, #e5e7eb)', maxWidth: '80%' }}>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="bodySmall" color="inherit">{m.text}</Text>
                      {m.timestamp && <Text variant="caption" size="xs" color="inherit" style={{ opacity: 0.7, textAlign: 'right' }}>{new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</Text>}
                    </Stack>
                  </Box>
                </Stack>
              );
            })}
          </Stack>
        </div>
      </Box>

      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-outline, #e5e7eb)' }}>
        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="end">
          <div style={{ flex: 1 }}>
            <LabelText as="label" variant="label" size="xs" htmlFor="chat-input-field">Compose Message</LabelText>
            <Input label="Compose Message" id="chat-input-field" value={val} onChange={setVal} onKeyDown={onKd} placeholder="Type your message..." />
          </div>
          <Button variant="primary" disabled={!val.trim()} onClick={send}>Send Message</Button>
        </Stack>
      </Box>
    </Card>
  );
}

