};

import React from 'react';
import {
  Container,
  Stack,
  Box,
  Text,
  Heading,
  Spinner,
  Divider,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * 
 * A responsive dashboard for monitoring real-time stock prices.
 * The component receives live data via the 'stocks' prop (Stream Contract).
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated,
}: Props) {

  const formatTime = (isoString?: string) => {
    if (!isoString) return 'Waiting for stream...';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return 'Updating...';
    }
  };

  const hasData = stocks && stocks.length > 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack gap={4}>
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
              Real-time stock monitoring dashboard
            </Text>
          </Stack>

          <Stack direction="horizontal" align="center" gap={12}>
             {!hasData && (
               <Stack direction="horizontal" gap={8} align="center">
                 <Spinner size={14} color="var(--ggui-color-primary-600, #0284c7)" />
                 <Text variant="caption" color="var(--ggui-color-primary-600, #0284c7)">
                   Connecting...
                 </Text>
               </Stack>
             )}
             <Box 
               paddingX={12} 
               paddingY={6} 
               borderRadius="var(--ggui-shape-radius-md, 8px)" 
               background="var(--ggui-color-surfaceVariant, #f4f4f5)"
               style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
             >
               <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                 Last Updated: {formatTime(lastUpdated)}
               </Text>
             </Box>
          </Stack>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

        {/* Dashboard Content */}
        {!hasData ? (
          <Box 
            padding={80} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-xl, 16px)"
            style={{ textAlign: 'center' }}
          >
            <Stack align="center" gap={24}>
              <Spinner size={40} />
              <Stack gap={4}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Initializing Data Stream
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
                  Establishing connection to live market updates...
                </Text>
              </Stack>
            </Stack>
          </Box>
        ) : (
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={24}>
            {stocks.map((stock, index) => {
              const changeVal = stock.change || 0;
              const isPositive = changeVal >= 0;
              const colorVar = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';
              const bgVar = isPositive
                ? 'var(--ggui-color-success-50, #f0fdf4)'
                : 'var(--ggui-color-error-50, #fef2f2)';

              return (
                <Box
                  key={`${stock.symbol}-${index}`}
                  padding="var(--ggui-spacing-6, 24px)"
                  borderRadius="var(--ggui-shape-radius-xl, 16px)"
                  background="var(--ggui-color-surface, #ffffff)"
                  style={{
                    border: `2px solid ${colorVar}`,
                    boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))',
                    transition: 'transform 0.2s ease-in-out',
                    animation: `ggui-fadeIn 300ms ease-out ${index * 50}ms both`,
                  }}
                >
                  <Stack gap={20}>
                    {/* Symbol and Status Badge */}
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={2}>
                        <Text weight="bold" size="3xl" color="var(--ggui-color-onSurface, #18181b)">
                          {stock.symbol || 'N/A'}
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" truncate>
                          {stock.name || 'Unspecified Asset'}
                        </Text>
                      </Stack>
                      <Box 
                        paddingX={8} 
                        paddingY={4} 
                        borderRadius="var(--ggui-shape-radius-sm, 4px)"
                        background={bgVar}
                      >
                        <Text variant="overline" color={colorVar} weight="bold">
                          {isPositive ? 'UP' : 'DOWN'}
                        </Text>
                      </Box>
                    </Stack>

                    <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                    {/* Price Content */}
                    <Stack gap={4}>
                      <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">
                        CURRENT PRICE
                      </Text>
                      <Text weight="bold" size="4xl" color="var(--ggui-color-onSurface, #18181b)">
                        ${(stock.price || 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                      </Text>
                    </Stack>

                    {/* Change Indicators */}
                    <Stack direction="horizontal" align="center" gap={12}>
                      <Text color={colorVar} weight="bold" size="lg">
                        {isPositive ? '+' : ''}{changeVal.toFixed(2)}
                      </Text>
                      <Box 
                        paddingX={10} 
                        paddingY={4} 
                        borderRadius="var(--ggui-shape-radius-full, 9999px)"
                        background={bgVar}
                        style={{ border: `1px solid ${colorVar}` }}
                      >
                        <Stack direction="horizontal" align="center" gap={6}>
                           <Text color={colorVar} weight="bold" size="sm">
                             {isPositive ? '▲' : '▼'}
                           </Text>
                           <Text color={colorVar} weight="bold" size="sm">
                             {Math.abs(stock.changePercent || 0).toFixed(2)}%
                           </Text>
                        </Stack>
                      </Box>
                    </Stack>
                  </Stack>
                </Box>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
