  Input,
  Select,
  Toggle,
  Button,
  Progress,
  Box,
  Divider,
  Badge,
  Spacer,
  Icon
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  complete: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, complete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? (avatarOptions ? avatarOptions[0] : ''),
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light',
  });

  const [emailError, setEmailError] = useState('');

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = useMemo(() => {
    return formData.name.trim() !== '' && isEmailValid(formData.email) && formData.avatar !== '';
  }, [formData.name, formData.email, formData.avatar]);

  const isStep2Valid = useMemo(() => {
    return formData.role !== '';
  }, [formData.role]);

  const updateField = (field: string, value: string | boolean) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'email' && typeof value === 'string') {
      setEmailError(value && !isEmailValid(value) ? 'Invalid format' : '');
    }
  };

  const progressValue = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap={24}>
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="end">
            <Heading level={2}>Account Setup</Heading>
            <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Step {step} of 3</Text>
          </Stack>
          <Progress value={progressValue} size="md" variant="default" />
        </Stack>

        <Card padding={32} shadow="md" radius="xl">
          <div style={{ animation: 'ggui-fadeIn 200ms ease-out' }} key={step}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Profile Setup</Heading>
                <Input label="Full Name" value={formData.name} onChange={(v) => updateField('name', v)} placeholder="Jane Doe" required />
                <Input label="Email Address" type="email" value={formData.email} onChange={(v) => updateField('email', v)} error={emailError} placeholder="jane@example.com" required />
                <Stack gap={12}>
                  <Text variant="label">Select Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map((emoji) => {
                      const isSelected = formData.avatar === emoji;
                      return (
                        <button
                          key={emoji}
                          type="button"
                          onClick={() => updateField('avatar', emoji)}
                          style={{
                            width: 'var(--ggui-spacing-12, 48px)',
                            height: 'var(--ggui-spacing-12, 48px)',
                            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                            fontSize: 'var(--ggui-font-size-xl, 20px)',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outline, #d4d4d8)',
                            background: isSelected ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
                            transition: 'all 200ms ease'
                          }}
                        >
                          {emoji}
                        </button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Preferences</Heading>
                <Select label="Current Role" value={formData.role} onChange={(v) => updateField('role', v)} options={roleOptions.map(r => ({ value: r, label: r }))} required />
                <Toggle label="Email notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
                <Divider margin={8} />
                <Stack gap={12}>
                  <Text variant="label">Theme Selection</Text>
                  <Stack direction="horizontal" gap={16} align="center">
                    <Text variant="bodySmall">Light</Text>
                    <Toggle checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
                    <Text variant="bodySmall">Dark</Text>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Final Review</Heading>
                <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
                  <Stack gap={20}>
                    <Stack direction="horizontal" gap={16} align="center">
                      <div style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', width: 'var(--ggui-spacing-12, 48px)', height: 'var(--ggui-spacing-12, 48px)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: 'var(--ggui-color-surface, #fafafa)', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>{formData.avatar}</div>
                      <Stack gap={4}>
                        <Heading level={4}>{formData.name}</Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={12}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                        <Badge variant="primary">{formData.role}</Badge>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                        <Text variant="bodySmall">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                        <Badge variant="secondary">{formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}</Badge>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Spacer size={32} />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" disabled={step === 1} onClick={() => setStep(step - 1)} leftIcon={<Icon name="chevron-left" size={16} />}>Go Back</Button>
            {step < 3 ? (
              <Button variant="primary" disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)} onClick={() => setStep(step + 1)} rightIcon={<Icon name="chevron-right" size={16} />}>Continue</Button>
            ) : (
              <Button variant="primary" onClick={() => complete(formData)} rightIcon={<Icon name="check" size={16} />}>Complete Setup</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
