import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button,
  Progress,
  Divider,
  Alert,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action: Submit the survey results */
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: string;
    features: string[];
    comments: string;
  }) => Promise<void> | void;
}

const EMAIL_PATTERN = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * MultiStepSurvey - A reusable 4-step survey form template with validation,
 * progress tracking, and a final review step.
 */
export default function MultiStepSurvey({
  featureOptions = ['Mobile App', 'Dashboard', 'API Access', 'Reporting', 'Support'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });

  const handleReset = () => {
    setCurrentStep(1);
    setSubmitStatus('idle');
    setFormData({
      name: '',
      email: '',
      satisfaction: '',
      features: [],
      comments: '',
    });
  };

  const isStep1Valid = useMemo(() => {
    return formData.name.trim().length > 0 && EMAIL_PATTERN.test(formData.email);
  }, [formData.name, formData.email]);

  const isStep2Valid = useMemo(() => {
    return formData.satisfaction !== '';
  }, [formData.satisfaction]);

  const isCurrentStepValid = () => {
    if (currentStep === 1) return isStep1Valid;
    if (currentStep === 2) return isStep2Valid;
    return true;
  };

  const handleNext = () => {
    if (currentStep < 5) setCurrentStep((p) => p + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep((p) => p - 1);
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      features: checked ? [...prev.features, feature] : prev.features.filter((f) => f !== feature),
    }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitStatus('idle');
    try {
      if (onSubmit) {
        await onSubmit(formData);
      }
      setSubmitStatus('success');
    } catch (err) {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const totalSteps = 4;
  const progressValue = (Math.min(currentStep, totalSteps) / totalSteps) * 100;

  if (submitStatus === 'success') {
    return (
      <Container maxWidth="md" padding="var(--ggui-spacing-12, 48px)">
        <Stack gap="var(--ggui-spacing-6, 24px)" align="center">
          <Alert variant="success" title="Survey Submitted">
            Feedback received!
          </Alert>
          <Button onPress={handleReset}>New Survey</Button>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2} align="center">Feedback Survey</Heading>
            <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {currentStep <= totalSteps ? `Step ${currentStep} of ${totalSteps}` : 'Review'}
            </Text>
          </Stack>
          <Progress value={progressValue} size="sm" />
        </Stack>

        <Card padding="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-8, 32px)">
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={4}>Personal Information</Heading>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text as="label" variant="label">Full Name *</Text>
                  <Input label="Full Name" required={true} placeholder="Name" value={formData.name} onChange={(v: string) => setFormData(p => ({...p, name: v}))} />
                </Stack>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text as="label" variant="label">Email Address *</Text>
                  <Input label="Email Address" required={true} type="email" placeholder="Email" value={formData.email} onChange={(v: string) => setFormData(p => ({...p, email: v}))} />
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={4}>Satisfaction</Heading>
                <RadioGroup label="Rating" value={formData.satisfaction} onChange={(v) => setFormData(p => ({ ...p, satisfaction: v }))} options={satisfactionLabels.map((l, i) => ({ label: l, value: String(i + 1) }))} />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={4}>Features</Heading>
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  {featureOptions.map((f) => (
                    <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={(c) => handleFeatureToggle(f, c)} />
                  ))}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={4}>Comments</Heading>
                <TextArea label="Comments" placeholder="Optional" value={formData.comments} onChange={(v) => setFormData(p => ({ ...p, comments: v }))} maxLength={500} showCount rows={5} />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={4}>Review Submission</Heading>
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                    <Text variant="body">{formData.name}</Text>
                  </Box>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                    <Text variant="body">{formData.email}</Text>
                  </Box>
                  <Divider margin="var(--ggui-spacing-2, 8px)" />
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features</Text>
                    <Text variant="body">{formData.features.join(', ') || 'None'}</Text>
                  </Box>
                </Stack>
                {submitStatus === 'error' && <Alert variant="error" title="Error">Failed to submit.</Alert>}
              </Stack>
            )}

            <Stack direction="horizontal" justify="between">
              <Button variant="ghost" disabled={currentStep === 1 || isSubmitting} onPress={handleBack}>Back</Button>
              {currentStep < 5 ? (
                <Button variant="primary" disabled={!isCurrentStepValid()} onPress={handleNext}>Next</Button>
              ) : (
                <Button variant="primary" loading={isSubmitting} onPress={handleSubmit}>Submit</Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Box,
  Heading,
  Container,
  Divider,
  Badge,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const getCategoryColors = (category: string = '') => {
  const cat = category.toLowerCase();
  if (cat.includes('alkali metal')) return { bg: 'var(--ggui-color-error-50, #fef2f2)', border: 'var(--ggui-color-error-300, #fca5a5)', text: 'var(--ggui-color-error-700, #b91c1c)' };
  if (cat.includes('alkaline earth')) return { bg: 'var(--ggui-color-warning-50, #fffbeb)', border: 'var(--ggui-color-warning-300, #fcd34d)', text: 'var(--ggui-color-warning-700, #b45309)' };
  if (cat.includes('transition metal')) return { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', border: 'var(--ggui-color-neutral-300, #d1d5db)', text: 'var(--ggui-color-neutral-700, #374151)' };
  if (cat.includes('post-transition')) return { bg: 'var(--ggui-color-success-50, #f0fdf4)', border: 'var(--ggui-color-success-300, #86efac)', text: 'var(--ggui-color-success-700, #15803d)' };
  if (cat.includes('metalloid')) return { bg: 'var(--ggui-color-info-50, #ecfeff)', border: 'var(--ggui-color-info-300, #67e8f9)', text: 'var(--ggui-color-info-700, #0e7490)' };
  if (cat.includes('noble gas')) return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', border: 'var(--ggui-color-primary-300, #7dd3fc)', text: 'var(--ggui-color-primary-800, #075985)' };
  if (cat.includes('halogen') || cat.includes('reactive nonmetal')) return { bg: 'var(--ggui-color-primary-50, #f0f9ff)', border: 'var(--ggui-color-primary-200, #bae6fd)', text: 'var(--ggui-color-primary-700, #0369a1)' };
  if (cat.includes('lanthanide')) return { bg: 'var(--ggui-color-neutral-50, #f9fafb)', border: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-neutral-600, #4b5563)' };
  if (cat.includes('actinide')) return { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', border: 'var(--ggui-color-neutral-400, #9ca3af)', text: 'var(--ggui-color-onSurface, #111827)' };

  return { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', border: 'var(--ggui-color-outline, #d4d4d8)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)' };
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return elements;
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    const unique = new Set(elements.map((el) => el.category).filter(Boolean));
    return Array.from(unique) as string[];
  }, [elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center" wrap gap={16}>
          <Stack gap={4}>
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interactive chemical element viewer.
            </Text>
          </Stack>
          <Box style={{ width: 'var(--ggui-spacing-80, 320px)' }}>
            <SearchField
              placeholder="Filter elements..."
              value={searchQuery}
              onChange={setSearchQuery}
              size="md"
            />
          </Box>
        </Stack>

        <Card padding="var(--ggui-spacing-4, 16px)" radius="md" shadow="none">
          <Stack direction="horizontal" gap={16} wrap align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Key:</Text>
            {categories.map((cat) => {
              const styles = getCategoryColors(cat);
              return (
                <Stack key={cat} direction="horizontal" gap={6} align="center">
                  <Box
                    style={{
