        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: 'var(--table-width, 1000px)',
            }}
          >
            {elements.map((el) => {
              const isMatch = filteredElements.includes(el);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const colors = getCategoryColors(el.category);

              return (
                <div
                  key={el.atomicNumber}
                  onClick={() => setSelectedElement(el)}
                  onKeyDown={(e) => { if (e.key === 'Enter') setSelectedElement(el); }}
                  role="button"
                  tabIndex={0}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    cursor: 'pointer',
                    transition: 'transform 200ms ease',
