        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Box,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages */
  messages: Array<Message>;
  /** Called when user sends a message. Payload: { text, timestamp } */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * Chat component.
 */
export default function GeneratedComponent(props: Props) {
  const { title = 'Chat', currentUser = 'User', participantCount = 0, messages = [], sendMessage } = props;
  const [inputText, setInputText] = useState('');
  const [chatMsgs, setChatMsgs] = useState<Message[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setChatMsgs(messages || []); }, [messages]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [chatMsgs]);

  const onSend = () => {
    if (!inputText.trim()) return;
    const ts = new Date().toISOString();
    sendMessage({ text: inputText, timestamp: ts });
    setChatMsgs(p => [...p, { sender: currentUser, text: inputText, timestamp: ts }]);
    setInputText('');
  };

  const formatTs = (iso?: string) => {
    if (!iso) return '';
    const d = new Date(iso);
    return isNaN(d.getTime()) ? '' : d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <Card padding={0} shadow="md" style={{ height: '600px', display: 'flex', flexDirection: 'column' }}>
      <Box padding="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between">
          <Text weight="bold">{title}</Text>
          <Badge variant="primary">{participantCount} Participants</Badge>
        </Stack>
      </Box>
      <Divider margin={0} />
      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-1, 4px)' }}>
        {chatMsgs.map((m, i) => {
          const isMe = m.sender === currentUser;
          const isSame = i > 0 && chatMsgs[i-1].sender === m.sender;
          return (
            <Box key={i} margin={isSame ? '0' : 'var(--ggui-spacing-3, 12px) 0 0 0'} style={{ alignSelf: isMe ? 'flex-end' : 'flex-start', maxWidth: '85%' }}>
              <Stack gap="var(--ggui-spacing-1, 4px)" align={isMe ? 'end' : 'start'}>
                {!isMe && !isSame && <Text variant="label" size="xs">{m.sender}</Text>}
                <Box padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)" background={isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surface)'} borderRadius={12}>
                  <Text color={isMe ? 'white' : 'black'} variant="bodySmall">{m.text}</Text>
                </Box>
                {(i === chatMsgs.length - 1 || chatMsgs[i+1].sender !== m.sender) && (
                  <Text variant="caption" size="xs">{formatTs(m.timestamp)}</Text>
                )}
              </Stack>
            </Box>
          );
        })}
      </div>
      <Divider margin={0} />
      <Box padding="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" align="end">
          <div style={{ flex: 1 }}>
            {/* @ts-ignore */}
            <Text as="label" htmlFor="chat-input" variant="label">Message Composer</Text>
            <Input label="Message Composer" id="chat-input" value={inputText} onChange={setInputText} placeholder="Type a message..." onKeyDown={e => e.key === 'Enter' && onSend()} />
          </div>
          <Button onClick={onSend} disabled={!inputText.trim()} variant="primary">Send Message</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Icon,
  Spinner,
  Box
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * Real-time stock dashboard with live updates from agent-data events.
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [displayStocks, setDisplayStocks] = useState<Stock[]>(stocks);
  const [updateTime, setUpdateTime] = useState<string | undefined>(
    initialLastUpdated
  );
  const [isConnected, setIsConnected] = useState(stocks.length > 0);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data && Array.isArray(data.stocks)) {
        setDisplayStocks(data.stocks);
        setUpdateTime(new Date().toISOString());
        setIsConnected(true);
      }
    };

    // Listen for agent-data broadcast on the global scope
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleAgentData);
    }

    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', handleAgentData);
      }
    };
  }, []);

  const formatTimestamp = (iso?: string) => {
    if (!iso) return 'Connecting...';
    try {
      return new Date(iso).toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch (e) {
      return iso;
    }
  };

  if (!isConnected && displayStocks.length === 0) {
    return (
      <Container padding={48} center>
        <Stack align="center" gap={16}>
          <Spinner size={32} />
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Connecting to Market Stream...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Live updates from agent stream
            </Text>
          </Stack>

          <Stack direction="horizontal" align="center" gap={8}>
             <div 
               style={{ 
                 width: 8, 
                 height: 8, 
                 borderRadius: '50%', 
                 backgroundColor: 'var(--ggui-color-success-500)',
                 boxShadow: '0 0 8px var(--ggui-color-success-500)' 
               }} 
             />
             <Text variant="label" size="sm" aria-live="polite">
               Last updated: {formatTimestamp(updateTime)}
             </Text>
          </Stack>
        </Stack>

        {/* Responsive Grid */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={20}>
          {displayStocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const semanticColor = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';
            const semanticBorder = isPositive
              ? 'var(--ggui-color-success-200, #bbf7d0)'
              : 'var(--ggui-color-error-200, #fecaca)';

            return (
              <Card 
                key={stock.symbol || `stock-${index}`} 
                padding={20} 
                radius="lg" 
                shadow="sm"
                style={{ 
                  border: `1px solid ${semanticBorder}`,
                  transition: 'transform 0.2s ease-in-out, border-color 0.2s',
                }}
              >
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap={0}>
                      <Text weight="bold" size="xl" style={{ lineHeight: 1 }}>
                        {stock.symbol || '---'}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" truncate>
                        {stock.name || '---'}
                      </Text>
                    </Stack>
                    <Icon 
                      name={isPositive ? 'chevron-up' : 'chevron-down'} 
                      size={20} 
                      color={semanticColor} 
                    />
                  </Stack>

                  <Stack gap={4}>
                    <Text size="3xl" weight="bold" style={{ letterSpacing: 'var(--ggui-letterSpacing-tight)' }}>
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" align="center" gap={4}>
                      <Text 
                        weight="medium" 
                        size="sm" 
                        color={semanticColor}
                      >
                        {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                      </Text>

                      <Box
                        paddingX={6}
                        paddingY={2}
                        background={isPositive ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-error-50, #fef2f2)'}
                        borderRadius="var(--ggui-shape-radius-sm)"
                      >
                        <Text 
                          variant="label" 
                          size="xs" 
                          style={{ 
                            color: semanticColor,
                            fontWeight: 700
                          }}
                        >
                          {(stock.changePercent ?? 0).toFixed(1)}%
                        </Text>
                      </Box>
                    </Stack>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<ForecastItem>;
}

/**
 * Helper to determine an appropriate emoji based on the condition string.
 */
const getWeatherEmoji = (condition: string = '') => {
  const lower = condition.toLowerCase();
  if (lower.includes('sun') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloud') || lower.includes('overcast')) return '☁️';
  if (lower.includes('rain') || lower.includes('drizzle')) return '🌧️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('snow') || lower.includes('ice')) return '❄️';
  if (lower.includes('wind') || lower.includes('breeze')) return '💨';
  if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
  return '🌡️';
};

/**
 * WeatherCard Component
 * Displays current weather details and a multi-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'C',
  forecast = [],
}: Props) {
  const currentEmoji = getWeatherEmoji(condition);

  return (
    <Card shadow="md" padding={24} radius="xl">
      <Stack direction="vertical" gap={24} align="stretch">

        {/* Header Section: City and Condition Icon */}
        <Stack direction="vertical" gap={8} align="center">
          <Heading level={2} align="center">
            {city}
          </Heading>

          <Box paddingY={8}>
            <Text size="4xl" align="center">
              <span role="img" aria-label={condition}>{currentEmoji}</span>
            </Text>
          </Box>

          {/* Large prominent Temperature */}
          <Stack direction="horizontal" gap={4} align="start" justify="center">
            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {Math.round(temperature)}
            </Text>
            <Box style={{ paddingTop: 'var(--ggui-spacing-1, 4px)' }}>
              <Text size="xl" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                °{unit}
              </Text>
            </Box>
          </Stack>

          <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition}
          </Text>
        </Stack>

        {/* Weather Details (Humidity & Wind) */}
        <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
          <Stack direction="horizontal" justify="around" align="center">
            <Stack direction="vertical" gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
            </Stack>

            <Box paddingY={8}>
              <Divider orientation="vertical" margin={0} color="var(--ggui-color-outline, #d4d4d8)" />
            </Box>

            <Stack direction="vertical" gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
              </Text>
            </Stack>
          </Stack>
        </Box>

        {/* 5-Day Forecast Strip */}
        {forecast && forecast.length > 0 && (
          <Stack direction="vertical" gap={16}>
            <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
            <Stack direction="horizontal" justify="between" align="stretch" wrap>
              {forecast.map((item, index) => (
                <Stack key={`forecast-${item.day || index}`} direction="vertical" gap={8} align="center">
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.day || '-'}
                  </Text>

                  <Text size="xl">
                    <span role="img" aria-hidden="true">
                      {item.icon || getWeatherEmoji(item.day || '')}
                    </span>
                  </Text>

                  <Stack direction="horizontal" gap={6} align="center">
                    <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {item.high !== undefined ? Math.round(item.high) : '-'}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.low !== undefined ? Math.round(item.low) : '-'}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        )}

      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Progress,
  Checkbox,
  RadioGroup,
  Divider,
  Box,
  Container,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Callback when the survey is submitted */
  onSubmit?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    featureOptions = ['Feature 1', 'Feature 2'], 
    satisfactionLabels = ['Bad', 'OK', 'Good'] 
  } = props;

  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [rating, setRating] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const s1Valid = name.trim() !== '' && isEmailValid;
  const s2Valid = rating !== '';

  const handleToggle = (f: string, c: boolean) => {
    setFeatures(p => c ? [...p, f] : p.filter(x => x !== f));
  };

  const handleSub = async () => {
    setLoading(true);
    if (props.onSubmit) {
      await props.onSubmit({ name, email, rating, features, comments });
    }
    setLoading(false);
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={32} radius="xl" border>
        <Stack gap={32}>
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between">
              <Heading level={3} color="var(--ggui-color-primary-600)">Survey</Heading>
              <Text variant="caption">{`Step ${step} of 4`}</Text>
            </Stack>
            <Progress value={(step / 4) * 100} />
          </Stack>

          <Box style={{ minHeight: '360px' }}>
            {step === 1 && (
              <Stack gap={24}>
                <Input label="Name" required value={name} onChange={setName} />
                <Input label="Email" required type="email" value={email} onChange={setEmail} />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <RadioGroup
                  label="Rating"
                  value={rating}
                  onChange={setRating}
                  options={satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: l }))}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={4}>Features</Heading>
                <Stack gap={12}>
                  {featureOptions.map(f => (
                    <Checkbox key={f} label={f} checked={features.includes(f)} onChange={(c) => handleToggle(f, c)} />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24}>
                <TextArea label="Comments" value={comments} onChange={setComments} maxLength={500} showCount rows={6} />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24}>
                <Heading level={4}>Review</Heading>
                <Box padding={20} borderRadius={12} background="var(--ggui-color-surfaceVariant)">
                  <Stack gap={12}>
                    <Text variant="bodySmall"><strong>Name:</strong> {name}</Text>
                    <Text variant="bodySmall"><strong>Email:</strong> {email}</Text>
                    <Text variant="bodySmall"><strong>Rating:</strong> {rating}</Text>
                    <Text variant="bodySmall"><strong>Features:</strong> {features.join(', ')}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={0} />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={() => setStep(s => s - 1)} disabled={step === 1 || loading}>Back</Button>
            {step < 5 ? (
              <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={(step === 1 && !s1Valid) || (step === 2 && !s2Valid)}>
                {step === 4 ? 'Review' : 'Next'}
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSub} loading={loading}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Text,
