/**
 * Maps category names to GGUI color scale tokens.
 * Based on the design specification.
 */
const getCategoryColors = (category: string = '') => {
  const cat = category.toLowerCase().replace(/[\s-]/g, '');

  if (cat.includes('alkalimetal')) {
    return {
      bg: 'var(--ggui-color-error-100, #fee2e2)',
      text: 'var(--ggui-color-error-800, #991b1b)',
      variant: 'error' as const
    };
  }
  if (cat.includes('alkalineearth')) {
    return {
      bg: 'var(--ggui-color-warning-100, #fef3c7)',
      text: 'var(--ggui-color-warning-800, #92400e)',
      variant: 'warning' as const
    };
  }
  if (cat.includes('transitionmetal')) {
    return {
      bg: 'var(--ggui-color-primary-100, #e0f2fe)',
      text: 'var(--ggui-color-primary-800, #075985)',
      variant: 'primary' as const
    };
  }
  if (cat.includes('posttransition') || cat.includes('halogen')) {
    return {
      bg: 'var(--ggui-color-info-100, #cffafe)',
      text: 'var(--ggui-color-info-800, #155e75)',
      variant: 'info' as const
    };
  }
  if (cat.includes('metalloid') || cat.includes('nonmetal')) {
    return {
      bg: 'var(--ggui-color-success-100, #dcfce7)',
      text: 'var(--ggui-color-success-800, #166534)',
      variant: 'success' as const
    };
  }
  if (cat.includes('noblegas')) {
    return {
      bg: 'var(--ggui-color-neutral-200, #e5e7eb)',
      text: 'var(--ggui-color-neutral-800, #1f2937)',
      variant: 'neutral' as const
    };
  }

  // Default for lanthanides, actinides, or unknown
  return {
    bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
    variant: 'default' as const
  };
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const uniqueCategories = useMemo(() => {
    const cats = elements.map(e => e.category).filter(Boolean) as string[];
    return Array.from(new Set(cats)).sort();
  }, [elements]);

  const filteredElements = useMemo(() => {
    if (!searchQuery) return elements.map(el => ({ ...el, isVisible: true }));
    const query = searchQuery.toLowerCase();
    return elements.map(el => ({
      ...el,
      isVisible: el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query)
    }));
  }, [elements, searchQuery]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Periodic Table of Elements</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Click an element to see more details
            </Text>
          </Stack>
          <Box style={{ minWidth: '300px' }}>
            <SearchField
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search by name or symbol..."
              size="md"
            />
          </Box>
        </Stack>

        {/* Periodic Table Grid */}
        <Box 
          style={{ 
            overflowX: 'auto', 
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
            scrollbarWidth: 'thin'
          }}
        >
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(50px, 1fr))',
              gridAutoRows: 'minmax(60px, auto)',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '1000px', // Prevents layout collapse
            }}
          >
            {filteredElements.map((el) => {
              const colors = getCategoryColors(el.category);
              const isMatch = (el as any).isVisible !== false;
              const isSelected = selectedElement?.symbol === el.symbol;

              return (
                <button
                  key={`${el.atomicNumber}-${el.symbol}`}
                  onClick={() => setSelectedElement(el)}
                  aria-label={`${el.name || 'Unknown'}, atomic number ${el.atomicNumber || 'Unknown'}, ${el.category || 'Unknown'}`}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    backgroundColor: colors.bg,
                    color: colors.text,
                    border: isSelected 
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    transition: 'transform 100ms ease, box-shadow 100ms ease, opacity 200ms ease',
                    opacity: isMatch ? 1 : 0.1,
                    pointerEvents: isMatch ? 'auto' : 'none',
                    transform: isSelected ? 'scale(1.05)' : 'none',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                    outline: 'none',
                    position: 'relative',
                    height: '100%',
                    width: '100%'
                  }}
                >
                  <Box style={{ width: '100%', textAlign: 'left' }}>
                    <Text variant="caption" style={{ fontSize: '10px', fontWeight: 600 }}>
                      {el.atomicNumber}
                    </Text>
                  </Box>
                  <Heading level={4} style={{ fontSize: '1.25rem', lineHeight: 1 }}>
                    {el.symbol}
                  </Heading>
                  <Box style={{ width: '100%', overflow: 'hidden' }}>
                    <Text truncate variant="caption" style={{ fontSize: '8px', opacity: 0.8 }}>
                      {el.name}
                    </Text>
                  </Box>
                </button>
              );
            })}
          </Box>
        </Box>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4, 16px)" shadow="none" border={false} style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>
          <Stack gap="var(--ggui-spacing-3, 12px)">
            <Text variant="label">Categories</Text>
            <Stack direction="horizontal" wrap gap="var(--ggui-spacing-3, 12px)">
              {uniqueCategories.map(cat => {
                const colors = getCategoryColors(cat);
                return (
                  <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)" key={cat}>
                    <Box 
                      borderRadius={4} 
                      style={{ 
                        width: '16px', 
                        height: '16px', 
                        backgroundColor: colors.bg, 
                        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' 
                      }} 
                    />
                    <Text variant="caption">{cat}</Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>

        {/* Detail Panel */}
        {selectedElement && (
          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }} aria-live="polite">
            <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="xl">
              <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="center" wrap>
                {/* Visual Representation */}
                <Box 
                  padding="var(--ggui-spacing-6, 24px)" 
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  style={{ 
                    backgroundColor: getCategoryColors(selectedElement.category).bg,
                    color: getCategoryColors(selectedElement.category).text,
                    minWidth: '120px',
                    textAlign: 'center'
                  }}
                >
                  <Text variant="overline" style={{ display: 'block', marginBottom: '8px' }}>
                    {selectedElement.atomicNumber}
                  </Text>
                  <Heading level={1} style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', margin: '8px 0' }}>
                    {selectedElement.symbol}
                  </Heading>
                  <Text variant="label">
                    {selectedElement.atomicWeight}
                  </Text>
                </Box>

                {/* Information */}
                <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: 1 }}>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Badge variant={getCategoryColors(selectedElement.category).variant as any} size="lg">
                      {selectedElement.category || 'N/A'}
                    </Badge>
                    <Heading level={2}>{selectedElement.name}</Heading>
                  </Stack>

                  <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: 'var(--ggui-spacing-4, 16px)' }}>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                      <Text weight="semibold">{selectedElement.atomicNumber}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                      <Text weight="semibold">{selectedElement.atomicWeight} u</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Symbol</Text>
                      <Text weight="semibold">{selectedElement.symbol}</Text>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import { Heading, Text, Stack, Box, Badge } from '@ggui-ai/design/primitives';
import { ChatWindow } from '@ggui-ai/design/compositions';

interface ChatMessage {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat title from props */
  title: string;
  /** Name of the current user */
  currentUser: string;
  /** Optional participant count */
  participantCount?: number;
  /** Messages list */
  messages: Array<ChatMessage>;
  /** Action: Send message */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * A real-time conversational interface.
 * Implements the converse interaction pattern.
 */
export default function ChatInterface(props: Props) {
  const [messages, setMessages] = useState<any[]>([]);

  useEffect(() => {
    const mapped = (props.messages || []).map((m, i) => ({
      id: `msg-${i}-${m.timestamp || Date.now()}`,
      content: m.text || '',
      sender: {
        id: m.sender || 'unknown',
        name: m.sender || 'Unknown',
      },
      timestamp: m.timestamp ? new Date(m.timestamp) : new Date(),
    }));
    setMessages(mapped);
  }, [props.messages]);

  // Stream Contract: Real-time agent messages
  useEffect(() => {
    const handleStreamEvent = (e: any) => {
      const d = e.detail;
      if (d?.text) {
        setMessages(p => [
          ...p,
          {
            id: `stream-${Date.now()}`,
            content: d.text,
            sender: { id: d.sender || 'Assistant', name: d.sender || 'Assistant' },
            timestamp: new Date(),
          }
        ]);
      }
    };

    // Listening for stream contract events
    addEventListener('ggui:agent-data', handleStreamEvent);
    return () => removeEventListener('ggui:agent-data', handleStreamEvent);
  }, []);

  const handleSend = (content: string) => {
    // Action Contract wiring
    props.sendMessage({ text: content, timestamp: new Date().toISOString() });
  };

  return (
    <div style={{ height: '600px', width: '100%', maxWidth: '768px', margin: '0 auto' }}>
      <ChatWindow
        header={
          <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surfaceVariant)" style={{ borderBottom: '1px solid var(--ggui-color-outline)' }}>
            <Stack direction="horizontal" align="center" justify="between">
              <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="center">
                <Heading level={3}>{props.title}</Heading>
                {props.participantCount !== undefined && (
                  <Badge variant="success" size="sm">
                    {props.participantCount} online
                  </Badge>
                )}
              </Stack>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Real-time</Text>
            </Stack>
          </Box>
        }
        messages={messages}
        currentUserId={props.currentUser}
        onSendMessage={handleSend}
        placeholder="Type your message..."
      />
    </div>
  );
}

export const __GGUI_META__ = {
  category: 'Communication',
  description: 'A complete real-time chat interface with messaging history and streaming support.'
};

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Box,
  Icon,
  Spinner,
  Badge
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard with real-time stream updates.
 * Follows the Broadcast interaction pattern via ggui:agent-data events.
 */
export default function StockDashboard(props: Props) {
  // Initialize state from props. The component will be kept in sync via stream events.
  const [liveStocks, setLiveStocks] = useState<Stock[]>(props.stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isLive, setIsLive] = useState(false);

  useEffect(() => {
    // Handler for the Stream Contract (ggui:agent-data)
    const handleStream = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (!data) return;

      setIsLive(true);

      // Merge new stock data into the existing array
      if (data.stocks && Array.isArray(data.stocks)) {
        setLiveStocks((current) => {
          const updated = [...current];
          data.stocks.forEach((newStock: Stock) => {
            const index = updated.findIndex((s) => s.symbol === newStock.symbol);
            if (index !== -1) {
              updated[index] = { ...updated[index], ...newStock };
            } else {
              updated.push(newStock);
            }
          });
          return updated;
        });
      }

      // Update the global update timestamp
      if (data.lastUpdated) {
        setLiveLastUpdated(data.lastUpdated);
      }
    };

    // Listen for agent updates as specified in the Stream Contract
    // We use the global reference to listen for the specific broadcast event
    addEventListener('ggui:agent-data', handleStream);
    return () => removeEventListener('ggui:agent-data', handleStream);
  }, []);

  // Sync state if initial props change
  useEffect(() => {
    setLiveStocks(props.stocks);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  const formatTime = (iso?: string) => {
    if (!iso) return 'N/A';
    try {
      const date = new Date(iso);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch (e) {
      return String(iso);
    }
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* Header with Title and Connection Status */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack direction="horizontal" gap={12} align="center">
            <Heading level={2}>Market Watch</Heading>
            {isLive ? (
              <Badge variant="success" size="sm" pill>Live Connected</Badge>
            ) : (
              <Stack direction="horizontal" gap={8} align="center">
                <Spinner size={16} />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Waiting for feed...
                </Text>
              </Stack>
            )}
          </Stack>

          <Stack direction="vertical" align="end" gap={0}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated
            </Text>
            <Text variant="label" weight="medium" aria-live="polite">
              {formatTime(liveLastUpdated)}
            </Text>
          </Stack>
        </Stack>

        {/* Responsive Grid of Stock Cards */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {liveStocks.map((stock) => {
            const isPositive = (stock.change || 0) >= 0;
            const trendColor = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';

            // Nested Box approach for custom-colored borders as per design spec
            const borderColor = isPositive 
              ? 'var(--ggui-color-success-500, #22c55e)' 
              : 'var(--ggui-color-error-500, #ef4444)';

            const iconName = isPositive ? 'chevron-up' : 'chevron-down';

            return (
              <Box 
                key={stock.symbol || Math.random().toString()}
                background={borderColor}
                padding={2}
                borderRadius={14}
              >
                <Box 
                  background="var(--ggui-color-surface, #ffffff)" 
                  padding={16} 
                  borderRadius={12}
                >
                  <Stack direction="vertical" gap={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      {/* Left: Ticker Symbol and Company Name */}
                      <Stack direction="vertical" gap={2}>
                        <Heading level={3}>
                          {stock.symbol || '---'}
                        </Heading>
                        <Text 
                          variant="bodySmall" 
                          color="var(--ggui-color-onSurfaceVariant)" 
                          truncate
                        >
                          {stock.name || 'Unknown Company'}
                        </Text>
                      </Stack>

                      {/* Right: Price and Change Amount */}
                      <Stack direction="vertical" align="end" gap={4}>
                        <Heading level={4}>
                          ${(stock.price || 0).toFixed(2)}
                        </Heading>
                        <Stack 
                          direction="horizontal" 
                          gap={4} 
                          align="center"
                          aria-label={isPositive ? "Positive change" : "Negative change"}
                        >
                          <Icon name={iconName} size={14} color={trendColor} />
                          <Text weight="semibold" color={trendColor} size="sm">
                            {isPositive ? '+' : ''}{(stock.change || 0).toFixed(2)} 
                            ({(stock.changePercent || 0).toFixed(2)}%)
                          </Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Box>
            );
          })}
        </CardGrid>

        {/* Fallback Empty State */}
        {liveStocks.length === 0 && (
          <Box 
            padding={48} 
            borderRadius={12} 
            background="var(--ggui-color-surfaceVariant)" 
            style={{ textAlign: 'center' }}
          >
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              No market data available.
            </Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Box,
  Divider,
  Container,
  Icon,
  Spacer
} from '@ggui-ai/design/primitives';

/** 
 * OnboardingWizard
 * 
 * A 3-step sequential onboarding flow.
 */

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
}

export default function OnboardingWizard(props: Props) {
  const { initialProfile, avatarOptions, roleOptions } = props;
  const complete = (props as any).complete;

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions[0]) || '👤',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  // Simple email validation regex
  const isEmailValid = (email: string) => /^\S+@\S+\.\S+$/.test(email);

  // Per-step validation
  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid(formData.email);
  const isStep2Valid = formData.role !== '';

  const handleNext = () => {
    if (currentStep < 3) setCurrentStep((prev) => prev + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep((prev) => prev - 1);
  };

  const handleComplete = () => {
    if (complete) {
      complete(formData);
    }
  };

  const progressPercent = (currentStep / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap={24}>
        {/* Step Indicator and Progress Bar */}
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="end">
            <Stack gap={4}>
              <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Onboarding flow</Text>
              <Heading level={2}>
                {currentStep === 1 ? 'Profile Setup' : currentStep === 2 ? 'Preferences' : 'Review & Confirm'}
              </Heading>
            </Stack>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep} / 3
            </Text>
          </Stack>
          <Progress value={progressPercent} size="md" variant="default" />
        </Stack>

        <Card padding={32} radius="xl" border shadow="md">
          <div style={{ animation: 'ggui-fadeIn 200ms ease-out' }} key={currentStep}>
            {currentStep === 1 && (
              <Stack gap={24}>
                <Heading level={4}>About You</Heading>

                <Input
                  label="Name"
                  id="onboarding-name"
                  placeholder="Enter your full name"
                  value={formData.name}
                  onChange={(val) => setFormData(prev => ({ ...prev, name: val }))}
                  required
                />

                <Input
                  label="Email"
                  id="onboarding-email"
                  type="email"
                  placeholder="name@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData(prev => ({ ...prev, email: val }))}
                  required
                  error={formData.email && !isEmailValid(formData.email) ? 'Please enter a valid email address' : undefined}
                />

                <Stack gap={12}>
                  <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">Select Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions && avatarOptions.map((emoji) => {
                      const active = formData.avatar === emoji;
                      return (
                        <button
                          key={emoji}
                          type="button"
                          onClick={() => setFormData(prev => ({ ...prev, avatar: emoji }))}
                          style={{
                            flex: 1,
                            minWidth: '64px',
                            height: '64px',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontSize: '28px',
                            cursor: 'pointer',
                            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                            border: `2px solid ${active ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                            backgroundColor: active ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #ffffff)',
                            transition: 'all 200ms ease',
                          }}
                          aria-label={`Select ${emoji} avatar`}
                          aria-pressed={active}
                        >
                          {emoji}
                        </button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={24}>
                <Heading level={4}>Customize Experience</Heading>

                <Select
                  label="What is your role?"
                  id="onboarding-role"
                  placeholder="Select a role..."
                  value={formData.role}
                  onChange={(val) => setFormData(prev => ({ ...prev, role: val }))}
                  options={roleOptions ? roleOptions.map(r => ({ value: r, label: r })) : []}
                  required
                />

                <Divider margin={8} />

                <Stack gap={16}>
                  <Toggle
                    label="Enable email notifications"
                    checked={formData.emailNotifications}
                    onChange={(val) => setFormData(prev => ({ ...prev, emailNotifications: val }))}
                  />
                  <Toggle
                    label={`App appearance: ${formData.theme === 'light' ? 'Light' : 'Dark'}`}
                    checked={formData.theme === 'dark'}
                    onChange={(val) => setFormData(prev => ({ ...prev, theme: val ? 'dark' : 'light' }))}
                  />
                </Stack>
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={24}>
                <Heading level={4}>Verify Selections</Heading>

                <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-xl, 16px)">
                  <Stack gap={20}>
                    <Stack direction="horizontal" gap={16} align="center">
                      <div style={{
                        width: '64px',
                        height: '64px',
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '32px',
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                        boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'
                      }}>
                        {formData.avatar}
                      </div>
                      <Stack gap={2}>
                        <Text weight="bold" size="lg">{formData.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                      </Stack>
                    </Stack>

                    <Divider margin={4} />

                    <Stack gap={12}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                        <Text weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                        <Text weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                        <Text weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Divider margin={24} />

          {/* Navigation Controls */}
          <Stack direction="horizontal" justify="between" align="center">
            {currentStep > 1 ? (
              <Button variant="ghost" onClick={handleBack} leftIcon={<Icon name="chevron-left" size={16} />}>
                Go Back
              </Button>
            ) : <Spacer size="flex" />}

            {currentStep < 3 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={(currentStep === 1 && !isStep1Valid) || (currentStep === 2 && !isStep2Valid)}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next Step
              </Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

