import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Progress,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Divider,
  Alert,
  Box
} from '@ggui-ai/design/primitives';

/**
 * MultiStepSurvey Component
 */

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: any) => void | Promise<void>;
}

export default function MultiStepSurvey({
  featureOptions = ['Analytics', 'Dashboards', 'API', 'Security', 'Mobile'],
  satisfactionLabels = ['1', '2', '3', '4', '5'],
  onSubmit
}: Props) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [step, setStep] = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [done, setDone] = useState(false);

  const TOTAL_STEPS = 5;
  const isEmailValid = email === '' || /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const radioOptions = useMemo(() => satisfactionLabels.map((l, i) => ({
    value: String(i + 1), label: `${i + 1} - ${l}`
  })), [satisfactionLabels]);

  if (done) {
    return (
      <Container maxWidth="md" padding={24}>
        <Alert variant="success" title="Success"><Text>Thank you!</Text></Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={32} radius="lg">
        <Stack gap={24}>
          <Stack gap={12}>
            <Heading level={2}>Survey</Heading>
            <Progress value={step + 1} max={TOTAL_STEPS} />
          </Stack>

          <Divider margin={0} />

          <Box>
            {error && <Alert variant="error" title="Error">{error}</Alert>}

            {step === 0 && (
              <Stack gap={20}>
                <Input label="Full Name" value={name} onChange={setName} required placeholder="Jane Doe" />
                <Input label="Email Address" type="email" value={email} onChange={setEmail} required error={!isEmailValid ? 'Error' : undefined} />
              </Stack>
            )}

            {step === 1 && (
              <RadioGroup label="Rate satisfaction" value={satisfaction} onChange={setSatisfaction} options={radioOptions} />
            )}

            {step === 2 && (
              <Stack gap={12}>
                <Text variant="label">Features</Text>
                {featureOptions.map(f => (
                  <Checkbox key={f} label={f} checked={features.includes(f)} onChange={c => setFeatures(p => c ? [...p, f] : p.filter(x => x !== f))} />
                ))}
              </Stack>
            )}

            {step === 3 && (
              <TextArea label="Comments" value={comments} onChange={setComments} maxLength={500} showCount rows={5} />
            )}

            {step === 4 && (
              <Stack gap={16}>
                <Heading level={4}>Review</Heading>
                <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius="8px">
                  <Text variant="body">Name: {name}</Text>
                  <Text variant="body">Email: {email}</Text>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={0} />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={() => setStep(s => s - 1)} disabled={step === 0 || submitting}>Back</Button>
            {step < TOTAL_STEPS - 1 ? (
              <Button onClick={() => setStep(s => s + 1)} disabled={step === 0 && (name === '' || email === '' || !isEmailValid)}>Next</Button>
            ) : (
              <Button onClick={async () => {
                setSubmitting(true);
                try {
                  if (onSubmit) await onSubmit({ name, email, satisfaction, features, comments });
                  setDone(true);
                } catch (e: any) {
                  setError(e.message);
                } finally {
                  setSubmitting(false);
                }
              }} loading={submitting}>Submit</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
