  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-400, #38bdf8)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  'metalloid': 'var(--ggui-color-success-500, #22c55e)',
  'polyatomic nonmetal': 'var(--ggui-color-success-600, #16a34a)',
  'diatomic nonmetal': 'var(--ggui-color-success-700, #15803d)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  'lanthanide': 'var(--ggui-color-error-400, #f87171)',
  'actinide': 'var(--ggui-color-warning-400, #fbbf24)',
  'unknown': 'var(--ggui-color-neutral-300, #d1d5db)',
};

/**
 * Maps an element category to a theme color variable.
 */
function getCategoryColor(category?: string): string {
  if (!category) return CATEGORY_COLORS['unknown'];
  const normalized = category.toLowerCase();
  const match = Object.keys(CATEGORY_COLORS).find(key => normalized.includes(key));
  return match ? CATEGORY_COLORS[match] : CATEGORY_COLORS['unknown'];
}

export default function PeriodicTable({ elements }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const safeElements = useMemo(() => Array.isArray(elements) ? elements : [], [elements]);

  const activeCategories = useMemo(() => {
    const cats = new Set<string>();
    safeElements.forEach(e => {
      if (e.category) cats.add(e.category);
    });
    return Array.from(cats).sort();
  }, [safeElements]);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return safeElements.filter(el => 
      !term || 
      el.name?.toLowerCase().includes(term) || 
      el.symbol?.toLowerCase().includes(term)
    );
  }, [safeElements, searchTerm]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Heading level={2}>Periodic Table of Elements</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Search and explore elements to view scientific properties.
          </Text>
        </Stack>

        {/* Search Control */}
        <Box>
          <SearchField
            placeholder="Search by name or symbol..."
            value={searchTerm}
            onChange={setSearchTerm}
            size="lg"
          />
        </Box>

        {/* Table Grid */}
        <Box 
          style={{ 
            overflowX: 'auto', 
            paddingBottom: 'var(--ggui-spacing-4, 16px)' 
          }}
        >
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '1100px',
            }}
          >
            {safeElements.map((el) => {
              const isMatch = !searchTerm || filteredElements.some(f => f.atomicNumber === el.atomicNumber);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const bgColor = getCategoryColor(el.category);

              return (
                <button
                  key={el.atomicNumber}
                  onClick={() => setSelectedElement(el)}
                  aria-label={`${el.name}, atomic number ${el.atomicNumber}`}
                  aria-pressed={isSelected}
                  style={{
                    gridColumn: el.col || 'auto',
                    gridRow: el.row || 'auto',
                    aspectRatio: '1',
                    backgroundColor: bgColor,
                    color: 'var(--ggui-color-surface, #ffffff)',
                    border: isSelected 
                      ? '3px solid var(--ggui-color-onSurface, #18181b)' 
                      : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center',
                    position: 'relative',
                    cursor: 'pointer',
                    opacity: isMatch ? 1 : 0.15,
                    transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                    zIndex: isSelected ? 10 : 1,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-lg)' : 'var(--ggui-shape-shadow-sm)',
                    outline: 'none',
                  }}
                >
                  <Text
                    as="span"
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-0-5, 2px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                      fontSize: '10px',
                      color: 'inherit',
                      fontWeight: 'var(--ggui-font-weight-medium, 500)',
                    }}
                  >
                    {el.atomicNumber}
                  </Text>
                  <Text
                    as="span"
                    style={{
                      fontSize: 'var(--ggui-font-size-xl, 20px)',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                      color: 'inherit',
                      lineHeight: 1,
                    }}
                  >
                    {el.symbol}
                  </Text>
                </button>
              );
            })}
          </div>
        </Box>

        {/* Legend */}
        <Stack direction="horizontal" wrap gap="var(--ggui-spacing-4, 16px)" align="center">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Classification Legend:</Text>
          {activeCategories.map((cat) => (
            <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
              <Box
                style={{
                  width: 'var(--ggui-spacing-3, 12px)',
                  height: 'var(--ggui-spacing-3, 12px)',
                  backgroundColor: getCategoryColor(cat),
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                }}
              />
              <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" style={{ textTransform: 'capitalize' }}>
                {cat}
              </Text>
            </Stack>
          ))}
        </Stack>

        {/* Detail View */}
        {selectedElement && (
          <Box style={{ animation: 'ggui-slideInUp 300ms cubic-bezier(0, 0, 0.2, 1)' }}>
            <Card shadow="md" padding="var(--ggui-spacing-8, 32px)" radius="xl">
              <Stack direction="horizontal" gap="var(--ggui-spacing-12, 48px)" align="center" wrap>
                <Box
                  style={{
                    width: '160px',
                    height: '160px',
                    backgroundColor: getCategoryColor(selectedElement.category),
                    color: 'var(--ggui-color-surface, #ffffff)',
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center',
                    position: 'relative',
                    flexShrink: 0,
                    boxShadow: 'var(--ggui-shape-shadow-md)',
                  }}
                >
                  <Text
                    as="span"
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-3, 12px)',
                      left: 'var(--ggui-spacing-4, 16px)',
                      fontSize: '20px',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      color: 'inherit',
                    }}
                  >
                    {selectedElement.atomicNumber}
                  </Text>
                  <Text
                    as="span"
                    style={{
                      fontSize: '64px',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                      color: 'inherit',
                      lineHeight: 1,
                    }}
                  >
                    {selectedElement.symbol}
                  </Text>
                </Box>

                <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: 1, minWidth: '300px' }}>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={2}>{selectedElement.name}</Heading>
                    <Text 
                      variant="bodyLarge" 
                      color="var(--ggui-color-onSurfaceVariant, #52525b)" 
                      style={{ textTransform: 'capitalize' }}
                    >
                      {selectedElement.category || 'Unknown category'}
                    </Text>
                  </Stack>

                  <Divider margin={0} />

                  <div style={{ 
                    display: 'grid', 
                    gridTemplateColumns: 'auto 1fr', 
                    gap: 'var(--ggui-spacing-3, 12px) var(--ggui-spacing-6, 24px)',
                    alignItems: 'baseline'
                  }}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Chemical Symbol</Text>
                    <Text variant="bodyLarge" weight="semibold">{selectedElement.symbol}</Text>

                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                    <Text variant="body">{selectedElement.atomicNumber}</Text>

                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text variant="body">{selectedElement.atomicWeight} u</Text>

