import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Heading,
  Badge,
  Box,
  Text,
  Input,
  Button,
  Avatar,
  Icon
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat title */
  title: string;
  /** Current user */
  currentUser: string;
  /** Participant count */
  participantCount?: number;
  /** Messages array */
  messages: Array<Message>;
  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface Component
 */
export default function ChatInterface({
  title = 'Chat',
  currentUser = 'User',
  participantCount,
  messages = [],
  sendMessage,
}: Props) {
  const [allMessages, setAllMessages] = useState<Message[]>(messages);
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  useEffect(() => {
    setAllMessages(messages);
  }, [messages]);

  useEffect(() => {
    const handleData = (event: any) => {
      if (event.detail) setAllMessages((prev) => [...prev, event.detail]);
    };
    addEventListener('ggui:agent-data', handleData);
    return () => removeEventListener('ggui:agent-data', handleData);
  }, []);

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    setAllMessages((prev) => [...prev, { sender: currentUser, ...payload }]);
    if (sendMessage) sendMessage(payload);
    setInputText('');
  };

  return (
    <Card shadow="md" padding={0} radius="lg" border>
      <div style={{ display: 'flex', flexDirection: 'column', height: '600px', width: '100%' }}>
        <Box padding={16} background="var(--ggui-color-surface, #fafafa)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" align="center" gap={12}>
            <Heading level={4}>{title}</Heading>
            {participantCount !== undefined && <Badge variant="secondary" size="sm">{participantCount} Participants</Badge>}
          </Stack>
        </Box>

        <div style={{ flex: 1, overflowY: 'auto', padding: '16px', backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
          <Stack gap={16}>
            {allMessages.map((m, i) => {
              const mine = m.sender === currentUser;
              return (
                <Stack key={i} direction="horizontal" align="end" gap={8} style={{ alignSelf: mine ? 'flex-end' : 'flex-start', maxWidth: '85%', flexDirection: mine ? 'row-reverse' : 'row' }}>
                  {!mine && <Box style={{ width: 32 }}><Avatar name={m.sender || 'U'} size="sm" /></Box>}
                  <Stack gap={4} style={{ alignItems: mine ? 'flex-end' : 'flex-start' }}>
                    <Box paddingX={16} paddingY={8} borderRadius={16} style={{ backgroundColor: mine ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>
                      <Text variant="body" color={mine ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>{m.text}</Text>
                    </Box>
                    <Text variant="caption" size="xs">{m.timestamp ? new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}</Text>
                  </Stack>
                </Stack>
              );
            })}
            <div ref={messagesEndRef} />
          </Stack>
        </div>

        <Box padding={16} background="var(--ggui-color-surface, #fafafa)" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" gap={8} align="end">
            <div style={{ flex: 1 }}>
              <Text as="label" {...({ htmlFor: 'msg-id' } as any)}>Message Input</Text>
              <Input label="Message Input" id="msg-id" value={inputText} onChange={setInputText} placeholder="Type a message..." size="md" onKeyDown={(e) => e.key === 'Enter' && handleSend()} />
            </div>
            <Button variant="primary" size="md" disabled={!inputText.trim()} onClick={handleSend} rightIcon={<Icon name="check" size={16} />}>Send</Button>
          </Stack>
        </Box>
      </div>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Text, 
  Heading, 
  Spinner, 
  Box 
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * A responsive dashboard for monitoring real-time stock prices.
 * The component updates automatically when the 'stocks' prop changes.
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated = ''
}: Props) {
  const [localStocks, setLocalStocks] = useState<Stock[]>(stocks);
  const [localLastUpdated, setLocalLastUpdated] = useState<string>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(stocks.length === 0);

  // Sync state with props. The agent updates this component by pushing new props.
  useEffect(() => {
    if (stocks && stocks.length > 0) {
      setLocalStocks(stocks);
      setIsConnecting(false);
    }
    if (lastUpdated) {
      setLocalLastUpdated(lastUpdated);
    }
  }, [stocks, lastUpdated]);

  const formatPrice = (val?: number) => {
    return (val ?? 0).toLocaleString('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2
    });
  };

  const formatTime = (iso?: string) => {
    if (!iso) return 'Waiting for update...';
    try {
      const date = new Date(iso);
      return isNaN(date.getTime()) ? iso : date.toLocaleTimeString();
    } catch {
      return '---';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Dashboard Header */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live data visualization dashboard
            </Text>
          </Stack>
          <Box 
            padding={8} 
            borderRadius="var(--ggui-shape-radius-md, 8px)" 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          >
            <Text variant="bodySmall" weight="medium">
              Update: {formatTime(localLastUpdated)}
            </Text>
          </Box>
        </Stack>

        {/* Content Section */}
        {isConnecting ? (
          <Box 
            padding={64} 
            borderRadius="var(--ggui-shape-radius-xl, 16px)" 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          >
            <Stack align="center" gap={16}>
              <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Connecting to live market data stream...
              </Text>
            </Stack>
          </Box>
        ) : (
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
            {localStocks.map((stock, idx) => {
              const change = stock.change ?? 0;
              const positive = change >= 0;
              const color = positive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';

              const background = positive
                ? 'var(--ggui-color-success-50, #f0fdf4)'
                : 'var(--ggui-color-error-50, #fef2f2)';

              const symbol = stock.symbol || 'SYM';

              return (
                <Card 
                  key={`${symbol}-${idx}`} 
                  padding={0} 
                  border 
                  radius="lg" 
                  shadow="sm"
                >
                  <Box 
                    padding={20} 
                    style={{ 
                      borderLeft: `4px solid ${color}`,
                      transition: 'border-color 200ms ease'
                    }}
                  >
                    <Stack gap={16}>
                      <Stack direction="horizontal" justify="between" align="start">
                        <Stack gap={2}>
                          <Text variant="bodyLarge" weight="bold">
                            {symbol}
                          </Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                            {stock.name || 'Financial Instrument'}
                          </Text>
                        </Stack>
                      </Stack>

                      <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {formatPrice(stock.price)}
                      </Text>

                      <Box 
                        paddingX={8} 
                        paddingY={4} 
                        borderRadius="var(--ggui-shape-radius-sm, 4px)" 
                        background={background}
                        style={{ width: 'fit-content' }}
                      >
                        <Stack direction="horizontal" gap={4} align="center">
                          <Text color={color} weight="semibold" size="sm">
                            {positive ? '▲' : '▼'} {positive ? '+' : ''}{change.toFixed(2)} ({positive ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}%)
                          </Text>
                        </Stack>
                      </Box>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  Icon
} from '@ggui-ai/design/primitives';

export interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

/**
 * A multi-step sequential form wizard for onboarding users.
 */
export default function GeneratedComponent(props: Props) {
  const { avatarOptions = [], roleOptions = [], initialProfile = {}, onComplete } = props;

  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions[0] || ''),
    role: initialProfile.role || (roleOptions[0] || ''),
    emailNotifications: initialProfile.emailNotifications !== false,
    theme: initialProfile.theme || 'light'
  });

  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email);
  const isS1Valid = data.name.trim() !== '' && isEmailValid;
  const isS2Valid = !!data.role;

  const update = (field: string, val: any) => setData(prev => ({ ...prev, [field]: val }));

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-8, 32px)" radius="xl" shadow="lg">
        <Stack gap="var(--ggui-spacing-8, 32px)">
          {/* Progress Section */}
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3}>
                {step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {step} of 3</Text>
            </Stack>
            <Progress value={(step / 3) * 100} size="sm" />
          </Stack>

          <div key={step} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {/* Step 1: Personal Information */}
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text as="label" variant="label" color="var(--ggui-color-neutral-700)">Full Name</Text>
                  <Input label="Name" placeholder="e.g. Jane Doe" value={data.name} onChange={v => update('name', v)} required />
                </Stack>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text as="label" variant="label" color="var(--ggui-color-neutral-700)">Email Address</Text>
                  <Input label="Email" type="email" placeholder="jane@example.com" value={data.email} onChange={v => update('email', v)} required error={data.email && !isEmailValid ? 'Invalid email format' : undefined} />
                </Stack>
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="label">Select Avatar</Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
                    {avatarOptions.map(emoji => (
                      <div
                        key={emoji}
                        onClick={() => update('avatar', emoji)}
                        onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && update('avatar', emoji)}
                        tabIndex={0}
                        role="button"
                        aria-label={`Select ${emoji}`}
                        style={{
                          cursor: 'pointer',
                          width: '56px',
                          height: '56px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: '24px',
                          borderRadius: 'var(--ggui-shape-radius-full)',
                          background: data.avatar === emoji ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
                          border: `2px solid ${data.avatar === emoji ? 'var(--ggui-color-primary-600, #0284c7)' : 'transparent'}`,
                          transition: 'all 200ms ease-in-out'
                        }}
                      >
                        {emoji}
                      </div>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* Step 2: System Preferences */}
            {step === 2 && (
              <Stack gap="var(--ggui-spacing-8, 32px)">
                <Select
                  label="Professional Role"
                  options={roleOptions.map(r => ({ value: r, label: r }))}
                  value={data.role}
                  onChange={v => update('role', v)}
                  required
                />
                <Box padding="var(--ggui-spacing-4, 16px)" borderRadius="var(--ggui-shape-radius-lg)" style={{ border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
                  <Stack gap="var(--ggui-spacing-6, 24px)">
                    <Stack direction="horizontal" justify="between" align="center">
                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        <Text variant="label">Email Notifications</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Receive updates about your account</Text>
                      </Stack>
                      <Toggle label="Notifications" checked={data.emailNotifications} onChange={v => update('emailNotifications', v)} />
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2, 8px)" />
                    <Stack direction="horizontal" justify="between" align="center">
                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        <Text variant="label">Dark Mode</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Switch interface to dark preference</Text>
                      </Stack>
                      <Toggle label="Dark Theme" checked={data.theme === 'dark'} onChange={v => update('theme', v ? 'dark' : 'light')} />
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}

            {/* Step 3: Summary Review */}
            {step === 3 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg)">
                  <Stack gap="var(--ggui-spacing-6, 24px)">
                    <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="center">
                      <div style={{
                        fontSize: '40px',
                        width: '72px',
                        height: '72px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        background: 'var(--ggui-color-surface, #fafafa)',
                        borderRadius: 'var(--ggui-shape-radius-full)',
                        boxShadow: 'var(--ggui-shape-shadow-sm)'
                      }}>
                        {data.avatar}
                      </div>
                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        <Text variant="bodyLarge" weight="bold">{data.name}</Text>
                        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">{data.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin="0" />
                    <Stack gap="var(--ggui-spacing-4, 16px)">
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Assigned Role</Text>
                        <Text variant="bodySmall" weight="medium">{data.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                        <Text variant="bodySmall" weight="medium">{data.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Selected Theme</Text>
                        <Text variant="bodySmall" weight="medium" style={{ textTransform: 'capitalize' }}>{data.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Divider margin="0" />

          {/* Navigation Controls */}
          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={() => setStep(s => s - 1)}
              disabled={step === 1}
              leftIcon={<Icon name="chevron-left" />}
            >
              Go Back
            </Button>
            {step < 3 ? (
              <Button
                variant="primary"
                onClick={() => setStep(s => s + 1)}
                disabled={(step === 1 && !isS1Valid) || (step === 2 && !isS2Valid)}
                rightIcon={<Icon name="chevron-right" />}
              >
                Next Step
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={() => onComplete?.(data)}
                leftIcon={<Icon name="check" />}
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

