import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Text,
  Heading,
  Box,
  Badge,
  Alert,
  Progress,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (answers: {
    name: string;
    email: string;
    satisfaction: string;
    features: string[];
    comments: string;
  }) => void | Promise<void>;
}

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface FormErrors {
  name: string;
  email: string;
}

export default function SurveyForm(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [submitting, setSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [submitError, setSubmitError] = useState('');

  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [errors, setErrors] = useState<FormErrors>({
    name: '',
    email: '',
  });

  const [touched, setTouched] = useState({
    name: false,
    email: false,
  });

  const isValidEmail = (email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validateStep = (step: number): boolean => {
    if (step === 1) {
      const newErrors: FormErrors = {
        name: formData.name.trim() ? '' : 'Name is required',
        email:
          formData.email.trim() === ''
            ? 'Email is required'
            : !isValidEmail(formData.email)
              ? 'Please enter a valid email'
              : '',
      };
      setErrors(newErrors);
      return !newErrors.name && !newErrors.email;
    }
    if (step === 2) {
      return formData.satisfaction !== '';
    }
    return true;
  };

  const handleNext = () => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = async () => {
    setSubmitting(true);
    setSubmitError('');
    try {
      if (props.onSubmit) {
        await props.onSubmit({
          name: formData.name,
          email: formData.email,
          satisfaction: formData.satisfaction,
          features: formData.features,
          comments: formData.comments,
        });
      }
      setSubmitSuccess(true);
    } catch (error) {
      setSubmitError(
        error instanceof Error ? error.message : 'Submission failed. Please try again.'
      );
    } finally {
      setSubmitting(false);
    }
  };

  const handleBlur = (field: 'name' | 'email') => {
    setTouched({ ...touched, [field]: true });
    validateStep(1);
  };

  const getSatisfactionLabel = (): string => {
    if (formData.satisfaction && props.satisfactionLabels.length > 0) {
      const idx = parseInt(formData.satisfaction, 10) - 1;
      return props.satisfactionLabels[idx] || '';
    }
    return '';
  };

  if (submitSuccess) {
    return (
      <Container maxWidth="md" padding={32}>
        <Card shadow="md" radius="lg" padding={32} border>
          <Stack gap={24} align="center">
            <Heading level={2} align="center">
              Thank You!
            </Heading>
            <Text variant="body" align="center">
              Your survey has been successfully submitted. We appreciate your feedback and will use it to improve our services.
            </Text>
            <Alert variant="success" title="Submission Complete">
              A confirmation has been sent to {formData.email}
            </Alert>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={32}>
      <Card shadow="md" radius="lg" padding={24} border>
        <div role="form" aria-label="Multi-step survey form">
          <Stack gap={24}>
            <Stack direction="horizontal" gap={16} align="center" justify="between">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {currentStep} of 5
              </Text>
              <Progress value={currentStep} max={5} variant="default" size="md" />
            </Stack>

            {currentStep === 1 && (
              <Stack gap={16}>
                <Heading level={3}>Personal Information</Heading>
                <Input
                  label="Full Name"
                  placeholder="John Doe"
                  value={formData.name}
                  onChange={(value) => setFormData({ ...formData, name: value })}
                  onBlur={() => handleBlur('name')}
                  error={touched.name ? errors.name : ''}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(value) => setFormData({ ...formData, email: value })}
                  onBlur={() => handleBlur('email')}
                  error={touched.email ? errors.email : ''}
                  helperText="We'll send you a copy of your responses"
                  required
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={16}>
                <Heading level={3}>Satisfaction Rating</Heading>
                <RadioGroup
                  label="Overall, how satisfied are you?"
                  value={formData.satisfaction}
                  onChange={(value) => setFormData({ ...formData, satisfaction: value })}
                  options={props.satisfactionLabels.map((label, idx) => ({
                    value: String(idx + 1),
                    label,
                  }))}
                  direction="vertical"
                />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Your feedback helps us improve
                </Text>
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={16}>
                <Heading level={3}>Feature Interests</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Which features are you most interested in?
                </Text>
                <Stack gap={12}>
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={formData.features.includes(feature)}
                      onChange={(checked) => {
                        const newFeatures = checked
                          ? [...formData.features, feature]
                          : formData.features.filter((f) => f !== feature);
                        setFormData({ ...formData, features: newFeatures });
                      }}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={16}>
                <Heading level={3}>Additional Feedback</Heading>
                <TextArea
                  label="Comments (Optional)"
                  placeholder="Share any additional thoughts or feedback..."
                  value={formData.comments}
                  onChange={(value) => setFormData({ ...formData, comments: value })}
                  rows={5}
                  maxLength={500}
                  showCount
                  helperText="Maximum 500 characters"
                />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap={20}>
                <Heading level={3}>Review Your Answers</Heading>

                <Box
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  padding={16}
                  borderRadius={8}
                >
                  <Stack gap={8}>
                    <Text variant="label" weight="semibold">
                      Personal Information
                    </Text>
                    <Text variant="body">
                      <strong>Name:</strong> {formData.name}
                    </Text>
                    <Text variant="body">
                      <strong>Email:</strong> {formData.email}
                    </Text>
                  </Stack>
                </Box>

                <Box
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  padding={16}
                  borderRadius={8}
                >
                  <Stack gap={8}>
                    <Text variant="label" weight="semibold">
                      Satisfaction
                    </Text>
                    <Text variant="body">
                      <strong>Rating:</strong> {getSatisfactionLabel()}
                    </Text>
                  </Stack>
                </Box>

                <Box
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  padding={16}
                  borderRadius={8}
                >
                  <Stack gap={8}>
                    <Text variant="label" weight="semibold">
                      Interested Features
                    </Text>
                    {formData.features.length > 0 ? (
                      <Stack direction="horizontal" gap={8} wrap>
                        {formData.features.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))}
                      </Stack>
                    ) : (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        No features selected
                      </Text>
                    )}
                  </Stack>
                </Box>

                <Box
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  padding={16}
                  borderRadius={8}
                >
                  <Stack gap={8}>
                    <Text variant="label" weight="semibold">
                      Comments
                    </Text>
                    <Text variant="body">
                      {formData.comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Box>

                <Alert variant="info">
                  Please review your answers before submitting. You can go back to edit any step.
                </Alert>

                {submitError && (
                  <Alert variant="error" title="Submission Error">
                    {submitError}
                  </Alert>
                )}
              </Stack>
            )}

            <Stack direction="horizontal" gap={12} justify="between">
              <Button
                variant="ghost"
                onClick={handleBack}
                disabled={currentStep === 1}
              >
                Back
              </Button>
              {currentStep < 5 ? (
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={
                    (currentStep === 1 && (!formData.name || !isValidEmail(formData.email))) ||
                    (currentStep === 2 && !formData.satisfaction)
                  }
                >
                  Next
                </Button>
              ) : (
                <Button
                  variant="primary"
                  onClick={handleSubmit}
                  disabled={submitting}
                  loading={submitting}
                >
                  Submit Survey
                </Button>
              )}
            </Stack>
          </Stack>
        </div>
      </Card>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Input,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<Element>;
}

// Category to color mapping
const categoryColorMap: Record<string, { bg: string; text: string; badge: 'primary' | 'success' | 'warning' | 'error' | 'info' | 'default' }> = {
  'nonmetal': {
    bg: 'var(--ggui-color-primary-50, #f0f9ff)',
    text: 'var(--ggui-color-primary-900, #0c4a6e)',
    badge: 'primary',
  },
  'noble-gas': {
    bg: 'var(--ggui-color-success-50, #f0fdf4)',
    text: 'var(--ggui-color-success-900, #14532d)',
    badge: 'success',
  },
  'halogen': {
    bg: 'var(--ggui-color-warning-50, #fffbeb)',
    text: 'var(--ggui-color-warning-900, #78350f)',
    badge: 'warning',
  },
  'alkali-metal': {
    bg: 'var(--ggui-color-error-50, #fef2f2)',
    text: 'var(--ggui-color-error-900, #7f1d1d)',
    badge: 'error',
  },
  'alkaline-earth-metal': {
    bg: 'var(--ggui-color-info-50, #ecfdf5)',
    text: 'var(--ggui-color-info-900, #164e63)',
    badge: 'info',
  },
  'transition-metal': {
    bg: 'var(--ggui-color-neutral-100, #f3f4f6)',
    text: 'var(--ggui-color-onSurface, #111827)',
    badge: 'default',
  },
  'lanthanide': {
    bg: 'var(--ggui-color-primary-100, #e0f2fe)',
    text: 'var(--ggui-color-primary-800, #075985)',
    badge: 'primary',
  },
  'actinide': {
    bg: 'var(--ggui-color-warning-100, #fef3c7)',
    text: 'var(--ggui-color-warning-800, #92400e)',
    badge: 'warning',
  },
  'metalloid': {
    bg: 'var(--ggui-color-neutral-100, #f3f4f6)',
    text: 'var(--ggui-color-onSurface, #1f2937)',
    badge: 'default',
  },
  'post-transition-metal': {
    bg: 'var(--ggui-color-neutral-100, #f3f4f6)',
    text: 'var(--ggui-color-onSurface, #111827)',
    badge: 'default',
  },
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  // Filter elements by search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        (el.symbol && el.symbol.toLowerCase().includes(query)) ||
        (el.name && el.name.toLowerCase().includes(query))
    );
  }, [elements, searchQuery]);

  // Get unique categories for legend
  const uniqueCategories = useMemo(() => {
    const categories = new Set<string>();
    elements.forEach((el) => {
      if (el.category) categories.add(el.category);
    });
    return Array.from(categories).sort();
  }, [elements]);

  // Clear selection if selected element is filtered out
  React.useEffect(() => {
    if (selectedElement && !filteredElements.find((el) => el.atomicNumber === selectedElement.atomicNumber)) {
      setSelectedElement(null);
    }
  }, [filteredElements, selectedElement]);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack direction="vertical" gap={24}>
        {/* Header Section */}
        <Stack direction="vertical" gap={16} align="center">
          <Heading level={2} align="center">
            Periodic Table of Elements
          </Heading>

          {/* Search Input */}
          <div style={{ width: '100%', maxWidth: '400px' }}>
            <Input
              label="Search elements"
              type="search"
              placeholder="Search by name or symbol..."
              value={searchQuery}
              onChange={setSearchQuery}
              size="md"
            />
          </div>

          {/* Legend */}
          {uniqueCategories.length > 0 && (
            <Stack direction="horizontal" gap={8} wrap={true} align="center" justify="center">
              {uniqueCategories.map((category) => {
                const colorInfo = categoryColorMap[category] || categoryColorMap['transition-metal'] || { badge: 'default' };
                return (
                  <Badge
                    key={category}
                    variant={colorInfo.badge}
                    size="sm"
                    pill
                  >
                    {category.replace(/-/g, ' ')}
                  </Badge>
                );
              })}
            </Stack>
          )}
        </Stack>

        {/* Periodic Table Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            width: '100%',
            padding: 'var(--ggui-spacing-4, 16px) 0',
          }}
        >
          {filteredElements.map((element) => {
            if (!element.row || !element.col) return null;

            const colorInfo = categoryColorMap[element.category || 'transition-metal'] || {
              bg: 'var(--ggui-color-neutral-50, #f9fafb)',
              text: 'var(--ggui-color-onSurface, #111827)',
            };

            return (
              <button
                key={element.atomicNumber}
                onClick={() =>
                  setSelectedElement(
                    selectedElement?.atomicNumber === element.atomicNumber ? null : element
                  )
                }
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  backgroundColor: colorInfo.bg,
                  color: colorInfo.text,
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px 0 rgba(0,0,0,0.05))',
                  cursor: 'pointer',
                  transition: 'all 200ms ease-in-out',
                  aspectRatio: '1',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  minHeight: '80px',
                  position: 'relative',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                }}
                aria-label={`Element: ${element.name || 'Unknown'}, symbol ${element.symbol}`}
              >
                <Stack direction="vertical" gap={4} align="center" justify="center">
                  {/* Atomic Number (top-left positioned via CSS) */}
                  <div style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)', width: '100%' }}>
                    <Text
                      as="span"
                      size="xs"
                      variant="overline"
                      color={colorInfo.text}
                    >
                      {element.atomicNumber}
                    </Text>
                  </div>

                  {/* Symbol (centered, large) */}
                  <Text
                    as="span"
                    size="2xl"
                    weight="bold"
                    color={colorInfo.text}
                    align="center"
                  >
                    {element.symbol || '-'}
                  </Text>

                  {/* Name (small, wrapped) */}
                  {element.name && (
                    <Text
                      as="span"
                      size="xs"
                      variant="caption"
                      color={colorInfo.text}
                      align="center"
                      truncate={true}
                    >
                      {element.name}
                    </Text>
                  )}
                </Stack>
              </button>
            );
          })}
        </div>

        {/* Detail Panel */}
        {selectedElement && (
          <>
            <Divider margin={16} />
            <Card shadow="md" padding={20} border={true}>
              <Stack direction="vertical" gap={12}>
                <Heading level={4}>
                  {selectedElement.name || 'Unknown Element'}
                </Heading>

                <Stack direction="horizontal" gap={24} wrap={true} align="start">
                  {/* Symbol */}
                  <Stack direction="vertical" gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                      Symbol
                    </Text>
                    <Text size="lg" weight="bold">
                      {selectedElement.symbol || 'N/A'}
                    </Text>
                  </Stack>

                  {/* Atomic Number */}
                  <Stack direction="vertical" gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                      Atomic Number
                    </Text>
                    <Text size="lg" weight="bold">
                      {selectedElement.atomicNumber || 'N/A'}
                    </Text>
                  </Stack>

                  {/* Atomic Weight */}
                  <Stack direction="vertical" gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                      Atomic Weight
                    </Text>
                    <Text size="lg" weight="bold">
                      {selectedElement.atomicWeight
                        ? selectedElement.atomicWeight.toFixed(2)
                        : 'N/A'}
                    </Text>
                  </Stack>

                  {/* Category */}
                  {selectedElement.category && (
                    <Stack direction="vertical" gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                        Category
                      </Text>
                      <Badge
                        variant={
                          categoryColorMap[selectedElement.category]?.badge || 'default'
                        }
                        size="md"
                        pill
                      >
                        {selectedElement.category.replace(/-/g, ' ')}
                      </Badge>
                    </Stack>
                  )}
                </Stack>
              </Stack>
            </Card>
          </>
        )}

        {/* Empty State */}
        {elements.length > 0 && filteredElements.length === 0 && (
          <Stack direction="vertical" gap={8} align="center" justify="center">
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #6b7280)" align="center">
              No elements match your search.
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #9ca3af)" align="center">
              Try searching with a different name or symbol.
            </Text>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Input,
  Button,
  Badge,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface MessageGroup {
  sender: string;
  messages: Message[];
}

export default function GeneratedComponent(props: Props) {
  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState<Message[]>(props.messages);
  const messageListRef = useRef<HTMLDivElement>(null);
  const lastMessageRef = useRef<HTMLDivElement>(null);

  const groupedMessages = useMemo(() => {
    const groups: MessageGroup[] = [];
    let currentGroup: MessageGroup | null = null;

    localMessages.forEach((msg) => {
      const sender = msg.sender || 'Unknown';
      if (!currentGroup || currentGroup.sender !== sender) {
        if (currentGroup) groups.push(currentGroup);
        currentGroup = { sender, messages: [msg] };
      } else {
        currentGroup.messages.push(msg);
      }
    });

    if (currentGroup) groups.push(currentGroup);
    return groups;
  }, [localMessages]);

  useEffect(() => {
    if (lastMessageRef.current) {
      lastMessageRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [localMessages]);

  useEffect(() => {
    setLocalMessages(props.messages);
  }, [props.messages]);

  useEffect(() => {
    if (typeof window === 'undefined') return;

    const handleIncomingMessage = (event: Event) => {
      const customEvent = event as CustomEvent;
      const newMessage = customEvent.detail as Message;
      if (newMessage && (newMessage.text || newMessage.sender)) {
        setLocalMessages((prev) => [...prev, newMessage]);
      }
    };

    window.addEventListener('ggui:agent-data', handleIncomingMessage);
    return () => {
      window.removeEventListener('ggui:agent-data', handleIncomingMessage);
    };
  }, []);

  const handleSend = () => {
    const trimmedText = inputValue.trim();
    if (!trimmedText) return;

    const payload = {
      text: trimmedText,
      timestamp: new Date().toISOString(),
    };

    if (props.onSendMessage) {
      props.onSendMessage(payload);
    }

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const isCurrentUser = (sender: string) => sender === props.currentUser;

  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  return (
    <Card
      shadow="md"
      border={true}
      radius="lg"
      padding={0}
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        maxHeight: '600px',
      }}
    >
      <Stack
        direction="horizontal"
        align="center"
        justify="between"
        gap={16}
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          borderTopLeftRadius: 'var(--ggui-shape-radius-lg, 12px)',
          borderTopRightRadius: 'var(--ggui-shape-radius-lg, 12px)',
        }}
      >
        <Heading
          level={4}
          color="var(--ggui-color-onSurface, #18181b)"
          style={{ margin: 0 }}
        >
          {props.title}
        </Heading>
        {props.participantCount !== undefined && (
          <Badge variant="primary" size="md" pill={true}>
            {props.participantCount}{' '}
            {props.participantCount === 1 ? 'participant' : 'participants'}
          </Badge>
        )}
      </Stack>

      <div
        style={{
          flex: 1,
          overflow: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-2, 8px)',
        }}
        ref={messageListRef}
        role="log"
        aria-label="Chat messages"
      >
        {groupedMessages.map((group, groupIdx) => {
          const isCurrent = isCurrentUser(group.sender);
          const alignment = isCurrent ? 'flex-end' : 'flex-start';
          const bgColor = isCurrent
            ? 'var(--ggui-color-primary-600, #0284c7)'
            : 'var(--ggui-color-surfaceVariant, #f4f4f5)';
          const textColor = isCurrent
            ? 'var(--ggui-color-neutral-50, #f9fafb)'
            : 'var(--ggui-color-onSurface, #18181b)';

          return (
            <div
              key={`group-${groupIdx}`}
              style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: alignment,
                gap: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {!isCurrent && (
                <Text
                  variant="label"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  size="sm"
                  style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                >
                  {group.sender}
                </Text>
              )}

              {group.messages.map((msg, msgIdx) => {
                return (
                  <Box
                    key={`msg-${groupIdx}-${msgIdx}`}
                    background={bgColor}
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    style={{
                      maxWidth: '70%',
                      wordWrap: 'break-word',
                      whiteSpace: 'pre-wrap',
                    }}
                  >
                    <Text
                      variant="body"
                      color={textColor}
                      style={{ margin: 0, marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                    >
                      {msg.text || ''}
                    </Text>
                    {msg.timestamp && (
                      <Text
                        variant="caption"
                        color={isCurrent ? 'rgba(249, 250, 251, 0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        style={{ margin: 0, fontSize: 'var(--ggui-font-size-xs, 12px)' }}
                      >
                        {formatTime(msg.timestamp)}
                      </Text>
                    )}
                  </Box>
                );
              })}
            </div>
          );
        })}
        <div ref={lastMessageRef} style={{ height: 0 }} />
      </div>

      <Stack
        direction="horizontal"
        gap={8}
        align="end"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          borderBottomLeftRadius: 'var(--ggui-shape-radius-lg, 12px)',
          borderBottomRightRadius: 'var(--ggui-shape-radius-lg, 12px)',
        }}
      >
        <Input
          label="Compose message"
          value={inputValue}
          onChange={setInputValue}
          onKeyDown={handleKeyDown}
          placeholder="Type a message..."
          type="text"
          style={{ flex: 1 }}
        />
        <Button
          variant="primary"
          size="md"
          onClick={handleSend}
          disabled={inputValue.trim().length === 0}
          aria-label="Send message"
        >
          Send
        </Button>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Spinner,
} from '@ggui-ai/design/primitives';

/**
 * Stock Ticker Dashboard Component
 * Displays stock prices in a responsive grid with live data updates via ggui:agent-data events.
 *
 * Props Contract:
 * - stocks: Array of stock objects with symbol, name, price, change, changePercent
 * - lastUpdated: ISO timestamp of last price update (optional)
 */

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Individual stock card component
 */
function StockCard({ stock }: { stock: Stock }): JSX.Element {
  const isPositive = (stock.changePercent ?? 0) >= 0;
  const textColor = isPositive
    ? 'var(--ggui-color-success-500, #22c55e)'
    : 'var(--ggui-color-error-500, #ef4444)';
  const borderColor = isPositive
    ? 'var(--ggui-color-success-500, #22c55e)'
    : 'var(--ggui-color-error-500, #ef4444)';
  const arrow = isPositive ? '▲' : '▼';

  return (
    <Card
      shadow="sm"
      padding={16}
      border={true}
      radius="lg"
      style={{
        borderColor: borderColor,
        borderWidth: '2px',
      }}
    >
      <Stack gap={12} direction="vertical">
        {/* Ticker Symbol - Large, Bold */}
        <Text
          variant="overline"
          weight="bold"
          size="2xl"
          color="var(--ggui-color-onSurface, #18181b)"
          as="span"
        >
          {stock.symbol || 'N/A'}
        </Text>

        {/* Company Name */}
        <Text
          variant="body"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          as="span"
        >
          {stock.name || 'Unknown'}
        </Text>

        {/* Current Price - Formatted with 2 decimals */}
        <Text
          variant="bodyLarge"
          weight="bold"
          color="var(--ggui-color-onSurface, #18181b)"
          as="span"
        >
          ${typeof stock.price === 'number' ? stock.price.toFixed(2) : '0.00'}
        </Text>

        {/* Change Amount and Percentage with Color Coding and Arrow */}
        <Stack gap={8} direction="horizontal" align="center">
          <Text
            variant="body"
            weight="semibold"
            color={textColor}
            as="span"
          >
            {stock.change !== undefined && stock.change >= 0 ? '+' : ''}
            {typeof stock.change === 'number' ? stock.change.toFixed(2) : '0.00'}
          </Text>
          <Text
            variant="body"
            weight="semibold"
            color={textColor}
            as="span"
          >
            {arrow}{' '}
            {typeof stock.changePercent === 'number'
              ? `${stock.changePercent >= 0 ? '+' : ''}${stock.changePercent.toFixed(2)}%`
              : '0.00%'}
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}

/**
 * Main StockTickerDashboard Component
 */
export default function StockTickerDashboard(props: Props): JSX.Element {
  const { stocks, lastUpdated } = props;
  const [displayStocks, setDisplayStocks] = useState<Stock[]>(stocks);
  const [isConnecting, setIsConnecting] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<
    'idle' | 'connecting' | 'connected' | 'error'
  >('idle');
  const listenerRef = useRef<((event: Event) => void) | null>(null);

  // Format timestamp for display
  const formatTimestamp = (iso?: string): string => {
    if (!iso) return 'Never';
    try {
      const date = new Date(iso);
      return date.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch {
      return 'Invalid date';
    }
  };

  // Setup event listener for live data broadcasts
  useEffect(() => {
    setConnectionStatus('connecting');
    setIsConnecting(true);

    // Define event listener
    const handleAgentData = (event: Event): void => {
      const customEvent = event as CustomEvent<{ stocks?: Stock[] }>;
      const data = customEvent.detail;

      // Update stocks if provided
      if (data?.stocks && Array.isArray(data.stocks)) {
        setDisplayStocks(data.stocks);
      }

      // Update connection status to connected
      setConnectionStatus('connected');
      setIsConnecting(false);
    };

    // Attach listener via EventTarget (safer access pattern)
    const target: EventTarget = typeof globalThis !== 'undefined' 
      ? (globalThis as unknown as EventTarget)
      : new EventTarget();

    listenerRef.current = handleAgentData;
    target.addEventListener('ggui:agent-data', listenerRef.current);

    // Cleanup timeout (consider connection failed after 5 seconds of no response)
    const timeout = setTimeout(() => {
      setConnectionStatus((prevStatus) => {
        if (prevStatus === 'connecting') {
          setIsConnecting(false);
          return 'error';
        }
        return prevStatus;
      });
    }, 5000);

    // Cleanup
    return () => {
      clearTimeout(timeout);
      if (listenerRef.current) {
        target.removeEventListener('ggui:agent-data', listenerRef.current);
      }
    };
  }, []);

  // Update display stocks when props change
  useEffect(() => {
    setDisplayStocks(stocks);
  }, [stocks]);

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24} direction="vertical">
        {/* Header with Title and Last Updated */}
        <Stack gap={12} direction="vertical">
          <Stack
            gap={16}
            direction="horizontal"
            justify="between"
            align="start"
          >
            <Heading
              level={1}
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Market Watch
            </Heading>

            {/* Connection Status Indicator */}
            <Stack gap={8} direction="horizontal" align="center">
              {isConnecting && (
                <>
                  <Spinner
                    size={16}
                    color="var(--ggui-color-primary-600, #0284c7)"
                  />
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    as="span"
                  >
                    Connecting...
                  </Text>
                </>
              )}
              {connectionStatus === 'connected' && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-success-500, #22c55e)"
                  as="span"
                >
                  ● Live
                </Text>
              )}
              {connectionStatus === 'error' && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-error-500, #ef4444)"
                  as="span"
                >
                  ⚠ Connection failed
                </Text>
              )}
            </Stack>
          </Stack>

          {/* Last Updated Timestamp */}
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            as="span"
          >
            Last Updated: {formatTimestamp(lastUpdated)}
          </Text>
        </Stack>

        {/* Responsive Grid of Stock Cards */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
            width: '100%',
          }}
        >
          {displayStocks.map((stock, index) => (
            <StockCard
              key={stock.symbol || `stock-${index}`}
              stock={stock}
            />
          ))}
        </div>

        {/* Empty State */}
        {displayStocks.length === 0 && (
          <Card padding={32} shadow="sm" radius="lg">
            <Stack
              gap={12}
              direction="vertical"
              align="center"
              justify="center"
            >
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                as="span"
              >
                No stocks to display
              </Text>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                as="span"
              >
                Add stocks to get started
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

'use client';

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Progress,
  Divider,
} from '@ggui-ai/design/primitives';

interface SelectOption {
  value: string;
  label: string;
}

interface RadioOption {
  value: string;
  label: string;
}

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: 'light' | 'dark';
}

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (profileData: ProfileData) => void;
}

const validateEmail = (email: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

export default function OnboardingWizard({
  initialProfile,
  avatarOptions = [],
  roleOptions = [],
  onComplete,
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || avatarOptions[0] || '',
    role: initialProfile?.role || roleOptions[0] || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: (initialProfile?.theme as 'light' | 'dark') || 'light',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const isCurrentStepValid = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (currentStep === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
      if (!formData.avatar) {
        newErrors.avatar = 'Please select an avatar';
      }
    } else if (currentStep === 2) {
      if (!formData.role) {
        newErrors.role = 'Please select a role';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (isCurrentStepValid()) {
      if (currentStep < 3) {
        setCurrentStep(currentStep + 1);
        setTouched({});
      }
    }
  };

  const handleComplete = () => {
    if (isCurrentStepValid()) {
      onComplete?.(formData);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
      setTouched({});
    }
  };

  const handleFieldChange = (field: keyof ProfileData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => {
        const newErrors = { ...prev };
        delete newErrors[field];
        return newErrors;
      });
    }
  };

  const handleFieldBlur = (field: string) => {
    setTouched((prev) => ({ ...prev, [field]: true }));
  };

  const roleSelectOptions: SelectOption[] = roleOptions.map((role) => ({
    value: role,
    label: role,
  }));

  const themeRadioOptions: RadioOption[] = [
    { value: 'light', label: 'Light' },
    { value: 'dark', label: 'Dark' },
  ];

  return (
    <Container maxWidth="lg" padding={32}>
      <Stack gap={24} direction="vertical">
        <Stack gap={12} direction="vertical" align="stretch">
          <Stack gap={8} direction="horizontal" align="center" justify="between">
            <Heading level={4}>Setup Progress</Heading>
            <Text variant="label">{`Step ${currentStep} of 3`}</Text>
          </Stack>
          <Progress value={currentStep} max={3} size="md" variant="default" />
        </Stack>

        <Divider margin={16} />

        {currentStep === 1 && (
          <Stack gap={24} direction="vertical">
            <Stack gap={8} direction="vertical">
              <Heading level={2}>Create Your Profile</Heading>
              <Text variant="body">Let's get to know you</Text>
            </Stack>

            <Stack gap={20} direction="vertical">
              <Input
                label="Full Name"
                placeholder="Enter your name"
                value={formData.name}
                onChange={(value) => handleFieldChange('name', value)}
                onBlur={() => handleFieldBlur('name')}
                error={touched.name ? errors.name : ''}
                required
                size="md"
              />

              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(value) => handleFieldChange('email', value)}
                onBlur={() => handleFieldBlur('email')}
                error={touched.email ? errors.email : ''}
                required
                size="md"
              />

              <Stack gap={12} direction="vertical" align="stretch">
                <Text variant="label" weight="semibold">
                  Choose Avatar
                </Text>
                <Stack gap={8} direction="horizontal" wrap={true} align="center">
                  {avatarOptions.map((emoji, index) => (
                    <Button
                      key={index}
                      variant={emoji === formData.avatar ? 'primary' : 'secondary'}
                      size="md"
                      onClick={() => handleFieldChange('avatar', emoji)}
                    >
                      {emoji}
                    </Button>
                  ))}
                </Stack>
                {touched.avatar && errors.avatar && (
                  <Text
                    variant="caption"
                    color="var(--ggui-color-error-500, #ef4444)"
                  >
                    {errors.avatar}
                  </Text>
                )}
              </Stack>
            </Stack>
          </Stack>
        )}

        {currentStep === 2 && (
          <Stack gap={24} direction="vertical">
            <Stack gap={8} direction="vertical">
              <Heading level={2}>Your Preferences</Heading>
              <Text variant="body">Customize your experience</Text>
            </Stack>

            <Stack gap={20} direction="vertical" align="stretch">
              <Select
                label="Role"
                placeholder="Select your role"
                value={formData.role}
                onChange={(value) => handleFieldChange('role', value)}
                onBlur={() => handleFieldBlur('role')}
                error={touched.role ? errors.role : ''}
                options={roleSelectOptions}
                required
                size="md"
              />

              <Toggle
                label="Receive email notifications"
                checked={formData.emailNotifications}
                onChange={(value) =>
                  handleFieldChange('emailNotifications', value)
                }
                size="md"
              />

              <RadioGroup
                label="Theme Preference"
                value={formData.theme}
                onChange={(value) =>
                  handleFieldChange('theme', value as 'light' | 'dark')
                }
                options={themeRadioOptions}
                direction="vertical"
              />
            </Stack>
          </Stack>
        )}

        {currentStep === 3 && (
          <Stack gap={24} direction="vertical">
            <Stack gap={8} direction="vertical">
              <Heading level={2}>Review Your Information</Heading>
              <Text variant="body">Verify everything looks good</Text>
            </Stack>

            <Card shadow="md" padding={24} radius="lg" border={true}>
              <Stack gap={20} direction="vertical" align="stretch">
                <Stack gap={12} direction="vertical" align="stretch">
                  <Text variant="label" weight="semibold">
                    Profile
                  </Text>
                  <Stack gap={12} direction="horizontal" align="center">
                    <Text as="span" style={{ fontSize: '40px', lineHeight: '1' }}>
                      {formData.avatar}
                    </Text>
                    <Stack gap={4} direction="vertical" align="start">
                      <Text weight="semibold">{formData.name}</Text>
                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        {formData.email}
                      </Text>
                    </Stack>
                  </Stack>
                </Stack>

                <Divider margin={12} />

                <Stack gap={12} direction="vertical" align="stretch">
                  <Text variant="label" weight="semibold">
                    Preferences
                  </Text>
                  <Stack gap={8} direction="vertical" align="stretch">
                    <Stack gap={8} direction="horizontal" justify="between" align="center">
                      <Text variant="body">Role:</Text>
                      <Text weight="semibold">{formData.role}</Text>
                    </Stack>
                    <Stack gap={8} direction="horizontal" justify="between" align="center">
                      <Text variant="body">Notifications:</Text>
                      <Text weight="semibold">
                        {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                      </Text>
                    </Stack>
                    <Stack gap={8} direction="horizontal" justify="between" align="center">
                      <Text variant="body">Theme:</Text>
                      <Text weight="semibold">
                        {formData.theme === 'light' ? 'Light' : 'Dark'}
                      </Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        <Divider margin={16} />

        <Stack
          gap={12}
          direction="horizontal"
          justify="between"
          align="center"
        >
          <Button
            variant="ghost"
            size="md"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Button
            variant="primary"
            size="md"
            onClick={currentStep === 3 ? handleComplete : handleNext}
            disabled={!isCurrentStepValid()}
          >
            {currentStep === 3 ? 'Complete Setup' : 'Next'}
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

