import React, { useState } from 'react';
import { Card, Stack, Text, Divider, Badge, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const c = condition.toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('partly') || c.includes('partial')) return '⛅';
  if (c.includes('cloud') || c.includes('overcast')) return '☁️';
  if (c.includes('rain') || c.includes('shower') || c.includes('drizzle')) return '🌧️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('snow') || c.includes('blizzard')) return '❄️';
  if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
  if (c.includes('wind') || c.includes('breezy')) return '💨';
  return '🌤️';
}

function getConditionGradient(condition: string): string {
  const c = condition.toLowerCase();
  if (c.includes('sun') || c.includes('clear')) {
    return 'linear-gradient(135deg, var(--ggui-color-warning-500, #f59e0b), var(--ggui-color-primary-500, #0ea5e9))';
  }
  if (c.includes('rain') || c.includes('shower') || c.includes('storm')) {
    return 'linear-gradient(135deg, var(--ggui-color-primary-700, #0369a1), var(--ggui-color-neutral-500, #6b7280))';
  }
  if (c.includes('snow')) {
    return 'linear-gradient(135deg, var(--ggui-color-primary-200, #bae6fd), var(--ggui-color-neutral-300, #d1d5db))';
  }
  if (c.includes('cloud') || c.includes('overcast')) {
    return 'linear-gradient(135deg, var(--ggui-color-neutral-500, #6b7280), var(--ggui-color-primary-400, #38bdf8))';
  }
  return 'linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))';
}

