import React, { useState, useCallback } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Box,
  Divider,
  Alert,
  Badge,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfactionRating: string;
  featureInterests: string[];
  comments: string;
}

const TOTAL_STEPS = 4;
const STEP_TITLES = [
  'Personal Information',
  'Satisfaction Rating',
  'Feature Interests',
  'Additional Comments',
];
const STEP_DESCRIPTIONS = [
  'Please provide your basic contact information.',
  'How satisfied are you with our product overall?',
  'Which features are you most interested in? Select all that apply.',
  'Any additional thoughts or suggestions? This field is optional.',
];

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

interface ReviewRowProps {
  label: string;
  value: string;
  isLong?: boolean;
}

function ReviewRow({ label, value, isLong }: ReviewRowProps) {
  return (
    <div style={{ display: 'flex', flexDirection: isLong ? 'column' : 'row', gap: isLong ? '4px' : '12px', alignItems: 'flex-start' }}>
      <div style={{ minWidth: isLong ? undefined : '110px', flexShrink: 0 }}>
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{label}:</Text>
      </div>
      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">{value}</Text>
    </div>
  );
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = ['Dashboard Analytics', 'API Integrations', 'Mobile App', 'Collaboration Tools', 'Custom Reports', 'Automated Workflows'],
    satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
    onSubmit,
  } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const MAX_CHARS = 500;

  const getNameError = useCallback((v: string): string => (v.trim() ? '' : 'Name is required'), []);
  const getEmailError = useCallback((v: string): string => {
    if (!v.trim()) return 'Email is required';
    if (!isValidEmail(v)) return 'Please enter a valid email address';
    return '';
  }, []);

  const handleNameChange = (value: string) => { setName(value); if (nameTouched) setNameError(getNameError(value)); };
  const handleEmailChange = (value: string) => { setEmail(value); if (emailTouched) setEmailError(getEmailError(value)); };
  const handleNameBlur = useCallback(() => { setNameTouched(true); setNameError(getNameError(name)); }, [name, getNameError]);
  const handleEmailBlur = useCallback(() => { setEmailTouched(true); setEmailError(getEmailError(email)); }, [email, getEmailError]);

  const handleNext = () => {
    if (currentStep === 1) {
      const nErr = getNameError(name); const eErr = getEmailError(email);
      setNameError(nErr); setEmailError(eErr); setNameTouched(true); setEmailTouched(true);
      if (nErr || eErr) return;
    }
    if (currentStep < TOTAL_STEPS) { setCurrentStep((s) => s + 1); } else { void handleSubmit(); }
  };

  const handleBack = () => { if (currentStep > 1) setCurrentStep((s) => s - 1); };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) => checked ? [...prev, feature] : prev.filter((f) => f !== feature));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitError('');
    const data: SurveyData = { name, email, satisfactionRating, featureInterests, comments };
    try {
      await new Promise<void>((resolve) => setTimeout(resolve, 800));
      onSubmit?.(data);
      setIsSubmitted(true);
    } catch {
      setSubmitError('Something went wrong. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const isNextDisabled = (): boolean => {
    if (currentStep === 1) return Boolean(getNameError(name) || getEmailError(email));
    if (currentStep === 2) return !satisfactionRating;
    return false;
  };

  const satisfactionOptions = satisfactionLabels.map((lbl, idx) => ({ value: String(idx + 1), label: `${idx + 1} — ${lbl}` }));
  const progressPercent = Math.round((currentStep / TOTAL_STEPS) * 100);
  const getSatisfactionDisplay = () => {
    if (!satisfactionRating) return '—';
    const idx = parseInt(satisfactionRating, 10) - 1;
    return `${satisfactionRating} — ${satisfactionLabels[idx] ?? ''}`;
  };

  if (isSubmitted) {
    return (
      <Box padding="var(--ggui-spacing-8, 32px)" background="var(--ggui-color-surface, #fafafa)">
        <MotionKeyframes />
        <div style={{ maxWidth: 560, margin: '0 auto', animation: 'ggui-scaleIn 300ms cubic-bezier(0.175,0.885,0.32,1.275) both' }}>
          <Card shadow="md" padding={48} radius="xl">
            <Stack gap={24} align="center">
              <div role="img" aria-label="Survey submitted successfully" style={{ width: 72, height: 72, borderRadius: '50%', background: 'var(--ggui-color-success-500, #22c55e)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                  <polyline points="20 6 9 17 4 12" />
                </svg>
              </div>
              <Stack gap={8} align="center">
                <Heading level={3} align="center">Thank You!</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                  Your survey response has been submitted successfully. We appreciate your valuable feedback!
                </Text>
              </Stack>
            </Stack>
          </Card>
        </div>
      </Box>
    );
  }

  return (
    <Box padding="var(--ggui-spacing-8, 32px)" background="var(--ggui-color-surface, #fafafa)">
      <MotionKeyframes />
      <div style={{ maxWidth: 600, margin: '0 auto' }}>
        <Stack gap={24}>

          <Stack gap={4} align="center">
            <Heading level={3} align="center" color="var(--ggui-color-onSurface, #18181b)">Customer Survey</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">Help us improve by sharing your experience</Text>
          </Stack>

          <Card shadow="sm" padding={20} radius="lg">
            <Stack gap={12}>
              <Stack direction="horizontal" justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Step {currentStep} of {TOTAL_STEPS}</Text>
                <Badge variant="primary" size="sm">{STEP_TITLES[currentStep - 1]}</Badge>
              </Stack>
              <Progress value={progressPercent} max={100} size="md" />
              <Stack direction="horizontal" gap={6}>
                {Array.from({ length: TOTAL_STEPS }, (_, i) => (
                  <div key={i} role="presentation" style={{ flex: 1, height: 4, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: i < currentStep ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)', transition: 'background 300ms ease' }} />
                ))}
              </Stack>
            </Stack>
          </Card>

          <Card shadow="md" padding={32} radius="xl">
            <Stack gap={24}>
              <Stack gap={6}>
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">{STEP_TITLES[currentStep - 1]}</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{STEP_DESCRIPTIONS[currentStep - 1]}</Text>
              </Stack>
              <Divider margin={0} />

              {currentStep === 1 && (
                <Stack gap={20}>
                  <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} error={nameError || undefined} required onBlur={handleNameBlur} />
                  <Input label="Email Address" placeholder="you@example.com" value={email} onChange={handleEmailChange} type="email" error={emailError || undefined} required onBlur={handleEmailBlur} />
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap={16}>
                  <RadioGroup label="Overall Satisfaction Rating" value={satisfactionRating} onChange={setSatisfactionRating} options={satisfactionOptions} direction="vertical" />
                  {satisfactionRating && (
                    <Box paddingX={16} paddingY={10} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                      <Stack direction="horizontal" gap={6} align="center">
                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--ggui-color-primary-600, #0284c7)" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                          <polyline points="20 6 9 17 4 12" />
                        </svg>
                        <Text variant="bodySmall" color="var(--ggui-color-primary-700, #0369a1)">
                          You selected:{' '}
                          <Text as="span" variant="bodySmall" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">{getSatisfactionDisplay()}</Text>
                        </Text>
                      </Stack>
                    </Box>
                  )}
                </Stack>
              )}

              {currentStep === 3 && (
                <Stack gap={10}>
                  {featureOptions.map((feature) => (
                    <Checkbox key={feature} label={feature} checked={featureInterests.includes(feature)} onChange={(checked) => handleFeatureToggle(feature, checked)} />
                  ))}
                  {featureInterests.length > 0 && (
                    <Box paddingX={12} paddingY={8} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                      <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">
                        {featureInterests.length} feature{featureInterests.length !== 1 ? 's' : ''} selected
                      </Text>
                    </Box>
                  )}
                </Stack>
              )}

              {currentStep === 4 && (
                <TextArea label="Additional Comments" placeholder="Share any additional thoughts, suggestions, or feedback..." value={comments} onChange={setComments} rows={6} maxLength={MAX_CHARS} showCount helperText="This field is optional. Maximum 500 characters." />
              )}
            </Stack>
          </Card>

          {currentStep === TOTAL_STEPS && (
            <Card shadow="sm" padding={24} radius="lg">
              <Stack gap={16}>
                <Stack direction="horizontal" align="center" gap={8}>
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="var(--ggui-color-primary-600, #0284c7)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
                    <polyline points="14 2 14 8 20 8" />
                    <line x1="16" y1="13" x2="8" y2="13" />
                    <line x1="16" y1="17" x2="8" y2="17" />
                  </svg>
                  <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Review Your Answers Before Submitting</Text>
                </Stack>
                <Divider margin={0} />
                <Stack gap={10}>
                  <ReviewRow label="Name" value={name || '—'} />
                  <ReviewRow label="Email" value={email || '—'} />
                  <ReviewRow label="Satisfaction" value={getSatisfactionDisplay()} />
                  <ReviewRow label="Interests" value={featureInterests.length > 0 ? featureInterests.join(', ') : 'None selected'} isLong />
                  <ReviewRow label="Comments" value={comments.trim() || 'No comments provided'} isLong />
                </Stack>
              </Stack>
            </Card>
          )}

          {submitError && (
            <Alert variant="error" title="Submission Failed" closable onClose={() => setSubmitError('')}>
              {submitError}
            </Alert>
          )}

          <nav aria-label="Survey step navigation">
            <Stack direction="horizontal" justify="between" align="center">
              <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1} size="md" aria-label="Go to previous step">← Back</Button>
              <Stack direction="horizontal" gap={12} align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{currentStep} of {TOTAL_STEPS}</Text>
                <Button variant="primary" onClick={handleNext} disabled={isNextDisabled() || isSubmitting} loading={isSubmitting} size="md" aria-label={currentStep === TOTAL_STEPS ? 'Submit Survey' : `Continue to step ${currentStep + 1}`}>
                  {currentStep === TOTAL_STEPS ? 'Submit Survey' : 'Next →'}
                </Button>
              </Stack>
            </Stack>
          </nav>

        </Stack>
      </div>
    </Box>
  );
}

