const DEFAULT_CLR = { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)', border: 'var(--ggui-color-outline, #d4d4d8)' };

function clrFor(category?: string) {
  if (!category) return DEFAULT_CLR;
  const lc = category.toLowerCase();
  for (const [k, v] of Object.entries(CAT_COLORS)) { if (lc.includes(k)) return v; }
  return DEFAULT_CLR;
}
function fmtWeight(w?: number) { return w == null ? '—' : w.toFixed(3); }
function cap(s?: string) { return s ? s.charAt(0).toUpperCase() + s.slice(1) : '—'; }

