// ──────────────────────────────────────────────────────────────
// Element cell component
// ──────────────────────────────────────────────────────────────
interface CellProps {
  el: ElementData;
  isLit: boolean;
  isSel: boolean;
  isHov: boolean;
  onSelect: () => void;
  onHoverIn: () => void;
  onHoverOut: () => void;
}

function ElementCell({ el, isLit, isSel, isHov, onSelect, onHoverIn, onHoverOut }: CellProps) {
  const c = clrFor(el.category);
  return (
    <button
      role="gridcell"
      aria-label={`${el.name ?? el.symbol ?? 'Unknown'}, atomic number ${el.atomicNumber ?? '?'}, ${el.category ?? 'unknown'}`}
      aria-pressed={isSel}
      onClick={onSelect}
      onMouseEnter={onHoverIn}
      onMouseLeave={onHoverOut}
      onFocus={(e) => { e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)'; e.currentTarget.style.outlineOffset = '2px'; }}
      onBlur={(e) => { e.currentTarget.style.outline = 'none'; e.currentTarget.style.outlineOffset = '0'; }}
      style={{
        gridRow: el.row, gridColumn: el.col,
        backgroundColor: isLit ? c.bg : 'var(--ggui-color-neutral-100, #f3f4f6)',
        border: isSel ? `2px solid ${c.border}` : `1px solid ${isLit ? c.border : 'var(--ggui-color-outline, #d4d4d8)'}`,
        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
        padding: 'var(--ggui-spacing-1, 4px) 2px',
        cursor: 'pointer',
        opacity: isLit ? 1 : 0.22,
        display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
        position: 'relative',
        minWidth: '44px',
        minHeight: 'var(--ggui-spacing-12, 48px)',
        transition: 'all 150ms ease-in-out',
        transform: isHov || isSel ? 'scale(1.1)' : 'scale(1)',
        boxShadow: isSel ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : isHov ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' : 'none',
        zIndex: isHov || isSel ? 2 : 1,
        outline: 'none', fontFamily: 'inherit',
      }}
    >
      <span style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)', fontSize: 'var(--ggui-font-size-xs, 12px)', color: isLit ? c.text : 'var(--ggui-color-onSurfaceVariant, #52525b)', lineHeight: 1, transform: 'scale(0.75)', transformOrigin: 'top left' }}>
        {el.atomicNumber}
      </span>
      <span style={{ fontSize: 'clamp(10px, 1.1vw, 16px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', color: isLit ? c.text : 'var(--ggui-color-onSurfaceVariant, #52525b)', lineHeight: 1, marginTop: 'var(--ggui-spacing-2, 8px)' }}>
        {el.symbol}
      </span>
      <span style={{ fontSize: '8px', color: isLit ? c.text : 'var(--ggui-color-onSurfaceVariant, #52525b)', lineHeight: 1, marginTop: 'var(--ggui-spacing-1, 4px)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', maxWidth: '100%', padding: '0 2px', opacity: 0.85 }}>
        {el.name}
      </span>
    </button>
  );
}

