export default function GeneratedComponent(props: Props) {
  const elements: ElementData[] = (props.elements && props.elements.length > 0) ? props.elements : DEFAULTS;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);
  const [hoveredEl, setHoveredEl] = useState<number | null>(null);

  const filteredSet = useMemo<Set<number | undefined> | null>(() => {
    if (!search.trim()) return null;
    const q = search.trim().toLowerCase();
    const s = new Set<number | undefined>();
    elements.forEach(el => { if (el.name?.toLowerCase().includes(q) || el.symbol?.toLowerCase().includes(q)) s.add(el.atomicNumber); });
    return s;
  }, [search, elements]);

  const categories = useMemo(() => {
    const c = new Set<string>();
    elements.forEach(el => { if (el.category) c.add(el.category.toLowerCase()); });
    return Array.from(c).sort();
  }, [elements]);

  const isLit = (el: ElementData) => !filteredSet || filteredSet.has(el.atomicNumber);
  const selClr = selected ? clrFor(selected.category) : DEFAULT_CLR;

  return (
    <Box padding={24} background="var(--ggui-color-surface, #fafafa)">

      <Stack gap={4} align="center">
        <Heading level={2} align="center" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Heading>
        <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Click any element for details · Search by name or symbol
        </Text>
      </Stack>

      <Box paddingY={16}>
        <Input label="Search elements" placeholder="e.g. Carbon, Au, noble gas…" value={search} onChange={setSearch} size="md" />
      </Box>

      <div style={{ overflowX: 'auto', width: '100%' }} role="region" aria-label="Periodic table">
        <div role="grid" aria-label="Periodic table of elements" style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))', gap: 'var(--ggui-spacing-1, 4px)', minWidth: '720px' }}>
          {elements.map((el) => {
            if (!el.row || !el.col) return null;
            const elIsLit = isLit(el);
            const elIsSel = selected?.atomicNumber === el.atomicNumber;
            const elIsHov = hoveredEl === el.atomicNumber;
            return (
              <ElementCell
                key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'x'}`}
                el={el}
                isLit={elIsLit}
                isSel={elIsSel}
                isHov={elIsHov}
                onSelect={() => setSelected(elIsSel ? null : el)}
                onHoverIn={() => setHoveredEl(el.atomicNumber ?? null)}
                onHoverOut={() => setHoveredEl(null)}
              />
            );
          })}
        </div>
      </div>

      {selected && (
        <Box paddingY={16}>
          <Card shadow="md" padding={24} radius="lg" border>
            <Stack direction="horizontal" gap={24} align="start">
              <div aria-hidden="true" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', background: selClr.bg, border: `2px solid ${selClr.border}`, minWidth: '80px', flexShrink: 0 }}>
                <span style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', color: selClr.text }}>{selected.atomicNumber}</span>
                <span style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', color: selClr.text, lineHeight: 1.1 }}>{selected.symbol}</span>
              </div>
              <Stack gap={12} style={{ flex: 1 }}>
                <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{selected.name}</Heading>
                <Stack direction="horizontal" gap={8} wrap>
                  <Badge variant="primary" size="md" pill>#{selected.atomicNumber}</Badge>
                  <Badge variant="default" size="md" pill>{cap(selected.category)}</Badge>
                </Stack>
                <Stack direction="horizontal" gap={24} wrap>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Symbol</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{selected.symbol}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{selected.atomicNumber}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{fmtWeight(selected.atomicWeight)}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{cap(selected.category)}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Period / Group</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{selected.row} / {selected.col}</Text>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        </Box>
      )}

      <Box paddingY={8}>
        <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Element Categories</Text>
        <Box paddingY={8}>
          <Stack direction="horizontal" gap={8} wrap>
            {categories.map(cat => {
              const c = clrFor(cat);
              return (
                <div key={cat} style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)', padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: c.bg, border: `1px solid ${c.border}` }}>
                  <span aria-hidden="true" style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: c.border, display: 'inline-block', flexShrink: 0 }} />
                  <Text variant="caption" color={c.text}>{cap(cat)}</Text>
                </div>
              );
            })}
          </Stack>
        </Box>
      </Box>
    </Box>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Stack, Text, Heading, Button, Badge, Box, Input, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Called when user sends a message. Payload: { text, timestamp } */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

// Workaround: cast Text so we can pass htmlFor to <label> element
const LabelText = Text as React.ComponentType<React.LabelHTMLAttributes<HTMLLabelElement> & {
  as?: string; variant?: string; color?: string; children?: React.ReactNode;
}>;

function formatTimestamp(iso?: string): string {
  if (!iso) return '';
  try {
    const date = new Date(iso);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

function MessageBubble({
  message,
  isOwn,
  showSender,
}: {
  message: Message;
  isOwn: boolean;
  showSender: boolean;
}) {
  return (
    <Box
      paddingX={16}
      paddingY={4}
      style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: isOwn ? 'flex-end' : 'flex-start',
        animation: 'ggui-slideInUp 200ms ease-out both',
      } as React.CSSProperties}
    >
      {showSender && !isOwn && (
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
          {message.sender}
        </Text>
      )}
      <Box
        paddingX={12}
        paddingY={8}
        borderRadius={isOwn ? '18px 18px 4px 18px' : '18px 18px 18px 4px'}
        background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
        style={{ maxWidth: '72%', wordBreak: 'break-word', boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' } as React.CSSProperties}
      >
        <Text
          variant="body"
          color={isOwn ? 'var(--ggui-color-neutral-50, #f9fafb)' : 'var(--ggui-color-onSurface, #18181b)'}
          as="span"
        >
          {message.text}
        </Text>
      </Box>
      {message.timestamp && (
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
          {formatTimestamp(message.timestamp)}
        </Text>
      )}
    </Box>
  );
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'Me',
    participantCount,
    messages = [],
    onSendMessage,
  } = props;

  const [localMessages, setLocalMessages] = useState<Message[]>(messages);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setLocalMessages(messages);
  }, [messages]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [localMessages]);

  // Stream Contract — ggui:agent-data via container node
  useEffect(() => {
    const node = containerRef.current;
    if (!node) return;
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data && (data.text || data.sender)) {
        setLocalMessages((prev) => [
          ...prev,
          {
            sender: data.sender ?? 'Agent',
            text: data.text ?? '',
            timestamp: data.timestamp ?? new Date().toISOString(),
          },
        ]);
      }
    };
    node.addEventListener('ggui:agent-data', handleAgentData);
    return () => { node.removeEventListener('ggui:agent-data', handleAgentData); };
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    setLocalMessages((prev) => [...prev, { sender: currentUser, text: trimmed, timestamp }]);
    if (onSendMessage) { onSendMessage({ text: trimmed, timestamp }); }
    setInputValue('');
  }, [inputValue, currentUser, onSendMessage]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
    },
    [handleSend]
  );

  return (
    <div
      ref={containerRef}
      style={{ height: '100%', display: 'flex', flexDirection: 'column', background: 'var(--ggui-color-surface, #fafafa)', fontFamily: 'inherit' }}
    >
      <MotionKeyframes />

      {/* ── Header ── */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0, padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', background: 'var(--ggui-color-primary-600, #0284c7)', borderBottom: '1px solid var(--ggui-color-primary-700, #0369a1)' }}>
        <Stack direction="horizontal" gap={8} align="center">
          <Heading level={5} color="var(--ggui-color-neutral-50, #f9fafb)">{title}</Heading>
        </Stack>
        {participantCount !== undefined && (
          <Badge variant="primary" size="sm" pill>
            {participantCount}{' '}{participantCount === 1 ? 'participant' : 'participants'}
          </Badge>
        )}
      </div>

      {/* ── Message List ── */}
      <div
        role="log"
        aria-label="Message list"
        aria-live="polite"
        style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', paddingTop: 'var(--ggui-spacing-2, 8px)', paddingBottom: 'var(--ggui-spacing-2, 8px)' }}
      >
        {localMessages.length === 0 && (
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 'var(--ggui-spacing-8, 32px)' }}>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
              No messages yet. Say hello!
            </Text>
          </div>
        )}
        {localMessages.map((message, index) => {
          const isOwn = message.sender === currentUser;
          const prevMessage = index > 0 ? localMessages[index - 1] : null;
          const showSender = !prevMessage || prevMessage.sender !== message.sender;
          return (
            <MessageBubble
              key={`${message.timestamp ?? ''}-${index}`}
              message={message}
              isOwn={isOwn}
              showSender={showSender}
            />
          );
        })}
        <div ref={messagesEndRef} aria-hidden="true" />
      </div>

      {/* ── Compose Area ── */}
      <div
        onKeyDown={handleKeyDown}
        style={{ flexShrink: 0, borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)', padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', background: 'var(--ggui-color-surface, #fafafa)', display: 'flex', alignItems: 'flex-end', gap: 'var(--ggui-spacing-2, 8px)' }}
      >
        <div style={{ flex: 1, minWidth: 0 }}>
          <LabelText as="label" variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" htmlFor="ggui-chat-compose">Message</LabelText>
          <Input label="Message" value={inputValue} onChange={setInputValue} placeholder="Type a message..." size="md" />
        </div>
        <Button variant="primary" size="md" onClick={handleSend} disabled={!inputValue.trim()} aria-label="Send message">
          Send
        </Button>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Text, Heading, Spinner } from '@ggui-ai/design/primitives';

interface StockItem {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: Array<StockItem>;
  lastUpdated?: string;
}

function formatPrice(price?: number): string {
  if (price == null) return '—';
  return price.toFixed(2);
}

function formatChange(change?: number): string {
  if (change == null) return '—';
  const sign = change >= 0 ? '+' : '';
  return `${sign}${change.toFixed(2)}`;
}

function formatPercent(pct?: number): string {
  if (pct == null) return '—';
  const sign = pct >= 0 ? '+' : '';
  return `${sign}${pct.toFixed(2)}%`;
}

function formatTimestamp(iso?: string): string {
  if (!iso) return 'N/A';
  try {
    return new Date(iso).toLocaleTimeString(undefined, {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  } catch {
    return iso;
  }
}

function getChangeColor(change?: number): string {
  if (change == null) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  if (change > 0) return 'var(--ggui-color-success-600, #16a34a)';
  if (change < 0) return 'var(--ggui-color-error-600, #dc2626)';
  return 'var(--ggui-color-onSurfaceVariant, #52525b)';
}

function getArrow(change?: number): string {
  if (change == null) return '';
  if (change > 0) return '▲';
  if (change < 0) return '▼';
  return '';
}

function getBorderColor(change?: number): string {
  if (change == null) return 'var(--ggui-color-outline, #d4d4d8)';
  if (change > 0) return 'var(--ggui-color-success-500, #22c55e)';
  if (change < 0) return 'var(--ggui-color-error-500, #ef4444)';
  return 'var(--ggui-color-outline, #d4d4d8)';
}

type ConnectionState = 'connecting' | 'live' | 'idle';

export default function GeneratedComponent(props: Props) {
  const rootRef = useRef<HTMLDivElement>(null);

  const safeStocks = Array.isArray(props?.stocks) ? props.stocks : [];

  const [stocks, setStocks] = useState<StockItem[]>(safeStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props?.lastUpdated);
  const [connectionState, setConnectionState] = useState<ConnectionState>(
    safeStocks.length > 0 ? 'idle' : 'connecting'
  );
  const [animatingSymbols, setAnimatingSymbols] = useState<Set<string>>(new Set());

  const animTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const connTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const next = Array.isArray(props?.stocks) ? props.stocks : [];
    setStocks(next);
    if (next.length > 0) setConnectionState((c) => (c === 'connecting' ? 'idle' : c));
  }, [props?.stocks]);

  useEffect(() => {
    setLastUpdated(props?.lastUpdated);
  }, [props?.lastUpdated]);

  const handleAgentData = useCallback((event: Event) => {
    const detail = (event as CustomEvent).detail;
    if (!detail) return;
    setConnectionState('live');
    if (Array.isArray(detail.stocks)) {
      const incoming: StockItem[] = detail.stocks;
      setStocks((prev) => {
        const prevMap = new Map(prev.map((s) => [s.symbol, s.price]));
        const changed = new Set<string>();
        incoming.forEach((s) => {
          if (s.symbol != null && prevMap.get(s.symbol) !== s.price) changed.add(s.symbol);
        });
        if (changed.size > 0) {
          setAnimatingSymbols(changed);
          if (animTimerRef.current) clearTimeout(animTimerRef.current);
          animTimerRef.current = setTimeout(() => setAnimatingSymbols(new Set()), 700);
        }
        return incoming;
      });
    }
    if (detail.lastUpdated) setLastUpdated(String(detail.lastUpdated));
  }, []);

  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    el.addEventListener('ggui:agent-data', handleAgentData);
    connTimerRef.current = setTimeout(() => {
      setConnectionState((curr) => (curr === 'connecting' ? 'idle' : curr));
    }, 2000);
    return () => {
      el.removeEventListener('ggui:agent-data', handleAgentData);
      if (connTimerRef.current) clearTimeout(connTimerRef.current);
      if (animTimerRef.current) clearTimeout(animTimerRef.current);
    };
  }, [handleAgentData]);

  const isConnecting = connectionState === 'connecting' && stocks.length === 0;
  const isEmpty = !isConnecting && stocks.length === 0;

  const panelBase: React.CSSProperties = {
    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
    backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
    boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
    padding: 'var(--ggui-spacing-12, 48px)',
    display: 'flex',
    flexDirection: 'column' as const,
    alignItems: 'center' as const,
    gap: 'var(--ggui-spacing-4, 16px)',
  };

  return (
    <div
      ref={rootRef}
      style={{
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        minHeight: '100vh',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <div style={{ maxWidth: 1280, margin: '0 auto', padding: 'var(--ggui-spacing-6, 24px)' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-6, 24px)' }}>

          {/* ── Header ── */}
          <header
            style={{
              background: 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))',
              borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
              padding: 'var(--ggui-spacing-6, 24px)',
              boxShadow: 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))',
            }}
          >
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 'var(--ggui-spacing-4, 16px)', flexWrap: 'wrap' }}>
              <div>
                <Heading level={1} color="var(--ggui-color-primary-50, #f0f9ff)">
                  Market Watch
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-primary-200, #bae6fd)">
                  Real-time stock prices
                </Text>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 'var(--ggui-spacing-2, 8px)' }}>
                {/* Connection state indicator */}
                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}>
                  <span
                    aria-hidden="true"
                    style={{
                      display: 'inline-block',
                      width: 'var(--ggui-spacing-2, 8px)',
                      height: 'var(--ggui-spacing-2, 8px)',
                      borderRadius: '50%',
                      flexShrink: 0,
                      backgroundColor:
                        connectionState === 'live'
                          ? 'var(--ggui-color-success-500, #22c55e)'
                          : connectionState === 'connecting'
                          ? 'var(--ggui-color-warning-500, #f59e0b)'
                          : 'var(--ggui-color-neutral-300, #d1d5db)',
                    }}
                  />
                  <Text variant="caption" color="var(--ggui-color-primary-100, #e0f2fe)">
                    {connectionState === 'live' ? 'Live' : connectionState === 'connecting' ? 'Connecting…' : 'Idle'}
                  </Text>
                </div>
                {/* Timestamp */}
                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}>
                  <Text variant="caption" color="var(--ggui-color-primary-200, #bae6fd)">
                    Last Updated:
                  </Text>
                  <Text
                    as="span"
                    variant="caption"
                    weight="medium"
                    color="var(--ggui-color-primary-50, #f0f9ff)"
                    aria-live="polite"
                  >
                    {formatTimestamp(lastUpdated)}
                  </Text>
                </div>
              </div>
            </div>
          </header>

          {/* ── Connecting ── */}
          {isConnecting ? (
            <div style={panelBase}>
              <Spinner size={40} />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                Connecting to market data stream…
              </Text>
            </div>
          ) : null}

          {/* ── Empty ── */}
          {isEmpty ? (
            <div style={{ ...panelBase, gap: 'var(--ggui-spacing-4, 16px)' }}>
              <Text size="2xl" align="center">📈</Text>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                No stock data available. Waiting for live updates…
              </Text>
            </div>
          ) : null}

          {/* ── Stock Grid ── */}
          {stocks.length > 0 ? (
            <div
              role="list"
              aria-label="Stock prices"
              aria-live="polite"
              aria-atomic="false"
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))',
                gap: 'var(--ggui-spacing-6, 24px)',
              }}
            >
              {stocks.map((stock, idx) => {
                const color = getChangeColor(stock.change);
                const border = getBorderColor(stock.change);
                const arrow = getArrow(stock.change);
                const arrowLabel = stock.change != null ? (stock.change >= 0 ? 'up' : 'down') : undefined;
                const changeDisplay =
                  arrow !== ''
                    ? `${arrow} ${formatPercent(stock.changePercent)}`
                    : formatPercent(stock.changePercent);
                const isAnimating = stock.symbol != null && animatingSymbols.has(stock.symbol);

                return (
                  <div
                    key={stock.symbol ?? idx}
                    role="listitem"
                    style={{
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      border: `2px solid ${border}`,
                      backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      padding: 'var(--ggui-spacing-6, 24px)',
                      boxShadow: isAnimating
                        ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                        : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                      transition: 'box-shadow 0.3s ease, border-color 0.3s ease',
                      boxSizing: 'border-box',
                    }}
                    aria-label={`${stock.symbol ?? 'Stock'} price card`}
                  >
                    {/* Ticker + arrow */}
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 'var(--ggui-spacing-1, 4px)' }}>
                      <Text as="span" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {stock.symbol ?? '—'}
                      </Text>
                      {arrow !== '' ? (
                        <span
                          aria-hidden="true"
                          style={{ fontSize: 'var(--ggui-font-size-xl, 20px)', color, lineHeight: '1' }}
                        >
                          {arrow}
                        </span>
                      ) : null}
                    </div>
                    {/* Company name */}
                    <div style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                        {stock.name ?? '—'}
                      </Text>
                    </div>
                    {/* Divider */}
                    <div
                      style={{
                        height: 1,
                        backgroundColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                        margin: 'var(--ggui-spacing-2, 8px) 0',
                      }}
                    />
                    {/* Price */}
                    <div style={{ marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
                      <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {`$${formatPrice(stock.price)}`}
                      </Text>
                    </div>
                    {/* Change + percent */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                      <Text variant="label" color={color}>
                        {formatChange(stock.change)}
                      </Text>
                      <span style={{ color: 'var(--ggui-color-outline, #d4d4d8)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
                        |
                      </span>
                      <Text as="span" variant="label" color={color} aria-label={arrowLabel}>
                        {changeDisplay}
                      </Text>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : null}

          {/* ── Footer ── */}
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
            Prices update automatically via live stream · All prices in USD
          </Text>

        </div>
      </div>
    </div>
  );
}
